var CMDS = [{"name": "ls", "emoji": "👀", "cat": "archivos", "simple": "Ver qué hay en una carpeta", "explain": "🧸 Imagina abrir tu cajón de juguetes y ver TODO lo que tienes. ¡ls te muestra todos los archivos y carpetas!", "example": "ls", "output": "fotos  musica  tareas.txt", "tipo": "comando"}, {"name": "ls -la", "emoji": "🔬", "cat": "archivos", "simple": "Ver todos los detalles de archivos", "explain": "🔬 Es como usar una lupa en tu cajón: ves los juguetes, cuándo los compraste y si están rotos o no.", "example": "ls -la", "output": "-rw-r--r-- 1 usuario 1024 tarea.txt", "tipo": "comando"}, {"name": "ls -lh", "emoji": "📏", "cat": "archivos", "simple": "Ver archivos con tamaño legible", "explain": "📐 Como ls -la pero los tamaños se ven bonitos: dice '1.2 MB' en vez de números raros.", "example": "ls -lh", "output": "-rw-r--r-- 1 usuario 1.2M foto.jpg", "tipo": "comando"}, {"name": "ls -lt", "emoji": "🕐", "cat": "archivos", "simple": "Ver archivos ordenados por fecha", "explain": "📅 Muestra los archivos del más nuevo al más viejo, ¡como ordenar fotos por cuándo se tomaron!", "example": "ls -lt", "output": "nuevo.txt  medio.txt  viejo.txt", "tipo": "comando"}, {"name": "ls -R", "emoji": "🌳", "cat": "archivos", "simple": "Ver archivos en todas las subcarpetas", "explain": "🗂️ Es como revisar no solo un cajón sino todos los cajones de todos los muebles de tu cuarto.", "example": "ls -R", "output": "./fotos:\nvacaciones.jpg\n./musica:\ncancion.mp3", "tipo": "comando"}, {"name": "cat", "emoji": "📖", "cat": "archivos", "simple": "Leer el contenido de un archivo", "explain": "📚 Es como abrir un libro y leer lo que dice. Le preguntas al archivo qué tiene escrito y él te lo muestra.", "example": "cat nota.txt", "output": "Hola, soy una nota!", "tipo": "comando"}, {"name": "cat -n", "emoji": "🔢", "cat": "archivos", "simple": "Leer archivo con números de línea", "explain": "📋 Como leer un libro pero con los números de página al lado de cada renglón.", "example": "cat -n tarea.txt", "output": "1  Hola\n2  Mundo", "tipo": "comando"}, {"name": "touch", "emoji": "✨", "cat": "archivos", "simple": "Crear un archivo vacío nuevo", "explain": "✏️ Es como sacar una hoja de papel en blanco. Creas un archivo nuevo sin nada escrito adentro.", "example": "touch mi_dibujo.txt", "output": "(archivo creado vacío)", "tipo": "comando"}, {"name": "cp", "emoji": "📋", "cat": "archivos", "simple": "Copiar un archivo", "explain": "🖨️ Como fotocopiar un dibujo. El original se queda y aparece una copia igualita en otro lugar.", "example": "cp foto.jpg copia_foto.jpg", "output": "(se crea copia_foto.jpg)", "tipo": "comando"}, {"name": "cp -r", "emoji": "📂", "cat": "archivos", "simple": "Copiar una carpeta completa", "explain": "📦 Como fotocopiar una caja llena de cosas. Copia la carpeta Y todo lo que hay adentro.", "example": "cp -r mis_fotos/ backup_fotos/", "output": "(carpeta copiada con todo)", "tipo": "comando"}, {"name": "mv", "emoji": "🚚", "cat": "archivos", "simple": "Mover o renombrar un archivo", "explain": "📦 Como agarrar un juguete y ponerlo en otra caja. También sirve para cambiarle el nombre.", "example": "mv viejo.txt nuevo.txt", "output": "(viejo.txt ahora es nuevo.txt)", "tipo": "comando"}, {"name": "rm", "emoji": "🗑️", "cat": "archivos", "simple": "Borrar un archivo", "explain": "🗑️ Como tirar un papel a la basura. ¡Cuidado! Una vez borrado, NO se puede recuperar fácil.", "example": "rm tarea_aburrida.txt", "output": "(archivo borrado para siempre)", "tipo": "comando"}, {"name": "rm -i", "emoji": "🤔", "cat": "archivos", "simple": "Borrar preguntando antes", "explain": "🙋 Como rm pero educado: antes de borrar te pregunta '¿estás seguro?' para que no borres algo importante.", "example": "rm -i importante.txt", "output": "¿Borrar importante.txt? (s/n)", "tipo": "comando"}, {"name": "rm -f", "emoji": "💥", "cat": "archivos", "simple": "Borrar sin preguntar nada", "explain": "⚠️ Borra sin preguntar ni avisar. ¡Muy peligroso! Solo úsalo si estás 100% seguro.", "example": "rm -f basura.tmp", "output": "(borrado sin preguntas)", "tipo": "comando"}, {"name": "ln", "emoji": "🔗", "cat": "archivos", "simple": "Crear un enlace duro a un archivo", "explain": "👯 Es como tener dos nombres para el mismo juguete. Si cambias uno, el otro también cambia.", "example": "ln original.txt enlace.txt", "output": "(enlace duro creado)", "tipo": "comando"}, {"name": "ln -s", "emoji": "🔀", "cat": "archivos", "simple": "Crear un acceso directo", "explain": "🏹 Como el acceso directo del escritorio de Windows. Apunta al archivo real pero está en otro lugar.", "example": "ln -s /ruta/real atajo", "output": "(acceso directo creado)", "tipo": "comando"}, {"name": "file", "emoji": "🔍", "cat": "archivos", "simple": "Saber qué tipo de archivo es", "explain": "🏷️ Como leer la etiqueta de una caja para saber si hay zapatos o juguetes. Te dice si es texto, imagen, etc.", "example": "file foto.jpg", "output": "foto.jpg: JPEG image data", "tipo": "comando"}, {"name": "stat", "emoji": "📊", "cat": "archivos", "simple": "Ver información detallada de un archivo", "explain": "🗂️ Como leer la ficha completa de un libro en la biblioteca: tamaño, fecha, permisos, todo.", "example": "stat tarea.txt", "output": "Tamaño: 1024  Modificado: 2026-03-08", "tipo": "comando"}, {"name": "wc", "emoji": "🔢", "cat": "archivos", "simple": "Contar palabras y líneas", "explain": "🧮 Como contar cuántas palabras tiene tu tarea. Te dice líneas, palabras y letras de un archivo.", "example": "wc tarea.txt", "output": "10  42  256 tarea.txt", "tipo": "comando"}, {"name": "wc -l", "emoji": "📏", "cat": "archivos", "simple": "Contar solo las líneas", "explain": "📋 Como contar cuántos renglones tiene tu cuaderno. Solo te dice el número de líneas.", "example": "wc -l lista.txt", "output": "25 lista.txt", "tipo": "comando"}, {"name": "wc -w", "emoji": "💬", "cat": "archivos", "simple": "Contar solo las palabras", "explain": "🗣️ Como contar cuántas palabras dijiste en un discurso. Solo cuenta las palabras.", "example": "wc -w redaccion.txt", "output": "342 redaccion.txt", "tipo": "comando"}, {"name": "diff", "emoji": "🔄", "cat": "archivos", "simple": "Ver diferencias entre dos archivos", "explain": "🕵️ Como jugar a 'encuentra las diferencias'. Muestra exactamente qué cambió entre dos archivos.", "example": "diff archivo1.txt archivo2.txt", "output": "&lt; texto antiguo\n&gt; texto nuevo", "tipo": "comando"}, {"name": "zip", "emoji": "🎒", "cat": "archivos", "simple": "Comprimir archivos en uno solo", "explain": "🗜️ Como meter mucha ropa en una maleta apretándola. Convierte muchos archivos en un paquetito pequeño.", "example": "zip fotos.zip foto1.jpg foto2.jpg", "output": "(crea fotos.zip)", "tipo": "comando"}, {"name": "unzip", "emoji": "📦", "cat": "archivos", "simple": "Descomprimir archivos zip", "explain": "🎁 Como abrir un regalo y sacar todo lo que hay dentro. Abre el paquete y saca los archivos.", "example": "unzip fotos.zip", "output": "foto1.jpg  foto2.jpg", "tipo": "comando"}, {"name": "tar -czf", "emoji": "🎁", "cat": "archivos", "simple": "Comprimir en formato tar.gz", "explain": "🏋️ Como envolver muchas cosas en papel burbuja y meterlas en una caja. Un formato muy común en Linux.", "example": "tar -czf backup.tar.gz mis_cosas/", "output": "(crea backup.tar.gz)", "tipo": "comando"}, {"name": "tar -xzf", "emoji": "📬", "cat": "archivos", "simple": "Descomprimir un archivo tar.gz", "explain": "📭 Como abrir la caja y quitar el papel burbuja. Extrae todos los archivos del paquete.", "example": "tar -xzf backup.tar.gz", "output": "(extrae todos los archivos)", "tipo": "comando"}, {"name": "gzip", "emoji": "💨", "cat": "archivos", "simple": "Comprimir un archivo con gzip", "explain": "🫁 Como exprimirle el aire a un globo para que ocupe menos. Comprime el archivo haciéndolo más pequeño.", "example": "gzip foto_grande.bmp", "output": "(crea foto_grande.bmp.gz)", "tipo": "comando"}, {"name": "gunzip", "emoji": "🎈", "cat": "archivos", "simple": "Descomprimir un archivo gzip", "explain": "🎈 Como inflar el globo de nuevo. Descomprime el archivo y lo deja como estaba.", "example": "gunzip foto.bmp.gz", "output": "(restaura foto_grande.bmp)", "tipo": "comando"}, {"name": "bzip2", "emoji": "🔩", "cat": "archivos", "simple": "Comprimir más fuerte que gzip", "explain": "💪 Como la hermana mayor de gzip: comprime más pequeño aunque tarda un poco más.", "example": "bzip2 archivo_grande.txt", "output": "(crea archivo_grande.txt.bz2)", "tipo": "instalar"}, {"name": "xz", "emoji": "⚡", "cat": "archivos", "simple": "Comprimir con máxima compresión", "explain": "🏆 El campeón de la compresión. Hace archivos muy pequeños pero tarda más tiempo.", "example": "xz datos.txt", "output": "(crea datos.txt.xz)", "tipo": "instalar"}, {"name": "md5sum", "emoji": "🔏", "cat": "archivos", "simple": "Calcular la huella digital de un archivo", "explain": "🧬 Como la huella dactilar de un archivo. Un código único para verificar que el archivo no fue cambiado.", "example": "md5sum foto.jpg", "output": "a1b2c3d4... foto.jpg", "tipo": "comando"}, {"name": "sha256sum", "emoji": "🔐", "cat": "archivos", "simple": "Calcular hash SHA256 de un archivo", "explain": "🔒 Como md5sum pero más seguro. Una huella digital aún más difícil de falsificar.", "example": "sha256sum programa.exe", "output": "abc123def456... programa.exe", "tipo": "comando"}, {"name": "split", "emoji": "✂️", "cat": "archivos", "simple": "Dividir un archivo en partes", "explain": "🧩 Como cortar un pastel en rebanadas. Divide un archivo grande en partes más pequeñas.", "example": "split -b 1M archivo_grande.iso parte_", "output": "parte_aa  parte_ab  parte_ac", "tipo": "comando"}, {"name": "truncate", "emoji": "🔪", "cat": "archivos", "simple": "Cambiar el tamaño de un archivo", "explain": "📐 Como recortar una hoja de papel. Puedes hacer el archivo más pequeño o más grande.", "example": "truncate -s 0 log.txt", "output": "(archivo vaciado a 0 bytes)", "tipo": "comando"}, {"name": "shred", "emoji": "🌪️", "cat": "archivos", "simple": "Borrar un archivo de forma segura", "explain": "🔥 Como pasar el archivo por una trituradora. Lo borra de forma que nadie pueda recuperarlo.", "example": "shred -u secreto.txt", "output": "(archivo destruido de forma segura)", "tipo": "comando"}, {"name": "tee", "emoji": "🍵", "cat": "archivos", "simple": "Ver y guardar la salida al mismo tiempo", "explain": "🔱 Como un grifo de agua en Y: lo que sale se va a dos lugares a la vez (pantalla Y archivo).", "example": "ls | tee lista.txt", "output": "(muestra en pantalla y guarda en lista.txt)", "tipo": "comando"}, {"name": "mktemp", "emoji": "🧪", "cat": "archivos", "simple": "Crear un archivo temporal único", "explain": "🗒️ Como sacar una nota adhesiva con nombre único para no confundirla con otras. Crea archivos temporales.", "example": "mktemp", "output": "/tmp/tmp.aB3xK9", "tipo": "comando"}, {"name": "pwd", "emoji": "📍", "cat": "directorios", "simple": "Ver en qué carpeta estás ahora", "explain": "🗺️ Tu GPS personal. Te dice exactamente en qué carpeta del sistema estás parado ahora mismo.", "example": "pwd", "output": "/home/usuario/documentos", "tipo": "comando"}, {"name": "cd", "emoji": "🚪", "cat": "directorios", "simple": "Entrar a una carpeta", "explain": "🚶 Como caminar de una habitación a otra. Le dices a qué cuarto quieres ir y ya estás ahí.", "example": "cd mis_fotos", "output": "(ahora estás en mis_fotos)", "tipo": "comando"}, {"name": "cd ..", "emoji": "⬆️", "cat": "directorios", "simple": "Subir a la carpeta anterior", "explain": "🏠 Los dos puntitos (..) significan 'volver atrás'. Como salir de un cuarto al pasillo.", "example": "cd ..", "output": "(volviste a la carpeta anterior)", "tipo": "comando"}, {"name": "cd ~", "emoji": "🏡", "cat": "directorios", "simple": "Ir a tu carpeta personal", "explain": "🏠 El símbolo ~ es tu casa. Sin importar dónde estés, este comando te lleva a tu carpeta personal.", "example": "cd ~", "output": "(estás en /home/usuario)", "tipo": "comando"}, {"name": "cd /", "emoji": "🌍", "cat": "directorios", "simple": "Ir a la raíz del sistema", "explain": "🌳 Como llegar a la raíz del árbol, el origen de todo. Es la carpeta más importante del sistema.", "example": "cd /", "output": "(estás en la raíz del sistema)", "tipo": "comando"}, {"name": "cd -", "emoji": "🔙", "cat": "directorios", "simple": "Volver a la carpeta anterior", "explain": "⏮️ Como el botón de 'atrás' del control remoto. Te lleva a la última carpeta donde estabas.", "example": "cd -", "output": "/home/usuario/descargas", "tipo": "comando"}, {"name": "mkdir", "emoji": "📁", "cat": "directorios", "simple": "Crear una carpeta nueva", "explain": "🆕 Como agarrar una caja vacía y ponerle nombre. Creas un lugar nuevo para guardar cosas.", "example": "mkdir mis_juegos", "output": "(carpeta mis_juegos creada)", "tipo": "comando"}, {"name": "mkdir -p", "emoji": "🏗️", "cat": "directorios", "simple": "Crear carpetas anidadas de una vez", "explain": "🪆 Como crear muñecas rusas: hace la carpeta y todas las que están adentro de una sola vez.", "example": "mkdir -p trabajo/2026/marzo", "output": "(crea trabajo/2026/marzo)", "tipo": "comando"}, {"name": "rmdir", "emoji": "🗑️", "cat": "directorios", "simple": "Borrar una carpeta vacía", "explain": "🗑️ Como tirar una caja vacía. Solo funciona si la carpeta no tiene nada adentro.", "example": "rmdir carpeta_vacia", "output": "(carpeta borrada)", "tipo": "comando"}, {"name": "rm -rf", "emoji": "💣", "cat": "directorios", "simple": "Borrar carpeta con todo adentro", "explain": "⚠️ Destruye la caja CON todo lo que hay dentro. ¡Muy peligroso! Borra TODO sin preguntar.", "example": "rm -rf carpeta_vieja", "output": "(TODO borrado, cuidado!)", "tipo": "comando"}, {"name": "tree", "emoji": "🌳", "cat": "directorios", "simple": "Ver carpetas como un árbol", "explain": "🌲 Dibuja un árbol familiar de tus carpetas. Muestra todo como las ramas de un árbol.", "example": "tree", "output": "├── fotos\n│   └── verano.jpg\n└── musica", "tipo": "instalar"}, {"name": "du", "emoji": "⚖️", "cat": "directorios", "simple": "Ver cuánto espacio ocupa una carpeta", "explain": "📏 Como pesar tu mochila. Te dice cuánto espacio en disco está usando una carpeta.", "example": "du -sh fotos/", "output": "256M  fotos/", "tipo": "comando"}, {"name": "du -h", "emoji": "📊", "cat": "directorios", "simple": "Ver tamaños en formato legible", "explain": "🔢 Como du pero te dice '1.5 GB' en vez de números incomprensibles. ¡Mucho más fácil!", "example": "du -h *", "output": "4.0K  nota.txt\n1.2G  videos/", "tipo": "comando"}, {"name": "du -s", "emoji": "🧮", "cat": "directorios", "simple": "Ver el tamaño total de una carpeta", "explain": "➕ Suma todo lo que hay en una carpeta y te da solo el total, sin listar cada archivo.", "example": "du -s documentos/", "output": "45000  documentos/", "tipo": "comando"}, {"name": "ls -d", "emoji": "📂", "cat": "directorios", "simple": "Ver solo carpetas (no archivos)", "explain": "📁 Como buscar solo las cajas en tu cuarto, ignorando todo lo que no sea una caja.", "example": "ls -d */", "output": "fotos/  musica/  videos/", "tipo": "comando"}, {"name": "find . -type d", "emoji": "🗂️", "cat": "directorios", "simple": "Buscar todas las carpetas", "explain": "🔍 Como un detector de cajas. Busca y lista todas las carpetas que hay desde donde estás.", "example": "find . -type d", "output": "./fotos\n./fotos/verano\n./musica", "tipo": "comando"}, {"name": "basename", "emoji": "📌", "cat": "directorios", "simple": "Obtener solo el nombre final de una ruta", "explain": "🏷️ De una dirección larga como '/casa/cuarto/juguete.txt', saca solo 'juguete.txt'.", "example": "basename /home/usuario/foto.jpg", "output": "foto.jpg", "tipo": "comando"}, {"name": "dirname", "emoji": "🗺️", "cat": "directorios", "simple": "Obtener la carpeta de una ruta", "explain": "🏠 De '/casa/cuarto/juguete.txt', te dice la parte de la casa: '/casa/cuarto'.", "example": "dirname /home/usuario/foto.jpg", "output": "/home/usuario", "tipo": "comando"}, {"name": "realpath", "emoji": "🔭", "cat": "directorios", "simple": "Ver la ruta completa y real", "explain": "📍 Si tienes un atajo o ruta relativa, te dice cuál es la dirección completa y real.", "example": "realpath ../foto.jpg", "output": "/home/usuario/fotos/foto.jpg", "tipo": "comando"}, {"name": "sudo", "emoji": "👑", "cat": "sistema", "simple": "Ejecutar como administrador", "explain": "🦸 Como tener los poderes del director de la escuela. Con sudo puedes hacer cosas normalmente prohibidas.", "example": "sudo apt install programa", "output": "(instalando con poderes de admin)", "tipo": "comando"}, {"name": "sudo -i", "emoji": "🎭", "cat": "sistema", "simple": "Convertirte en administrador", "explain": "🦸‍♂️ Como ponerse el traje de superhéroe y quedárselo. Todas las acciones siguientes serán de administrador.", "example": "sudo -i", "output": "root@maquina:#", "tipo": "comando"}, {"name": "su", "emoji": "🔄", "cat": "sistema", "simple": "Cambiar a otro usuario", "explain": "🎭 Como disfrazarte de otra persona. Cambias tu identidad en la computadora por la de otro usuario.", "example": "su pedro", "output": "(ahora eres pedro)", "tipo": "comando"}, {"name": "echo", "emoji": "📢", "cat": "sistema", "simple": "Mostrar texto en pantalla", "explain": "🗣️ Como un loro que repite lo que le dices. Escribe algo y lo muestra en pantalla.", "example": "echo Hola Mundo", "output": "Hola Mundo", "tipo": "comando"}, {"name": "clear", "emoji": "🧹", "cat": "sistema", "simple": "Limpiar la pantalla", "explain": "🧽 Como borrar el pizarrón. Quita todo el texto y te deja una pantalla limpia.", "example": "clear", "output": "(pantalla limpia!)", "tipo": "comando"}, {"name": "history", "emoji": "📜", "cat": "sistema", "simple": "Ver comandos usados antes", "explain": "🕰️ Un diario que anota todo lo que hiciste. Puedes ver todos los comandos anteriores.", "example": "history", "output": "1  ls\n2  cd fotos\n3  cat nota.txt", "tipo": "comando"}, {"name": "history -c", "emoji": "🧹", "cat": "sistema", "simple": "Borrar el historial de comandos", "explain": "🗑️ Como borrar las páginas del diario. Elimina toda la memoria de lo que escribiste.", "example": "history -c", "output": "(historial borrado)", "tipo": "comando"}, {"name": "date", "emoji": "📅", "cat": "sistema", "simple": "Ver la fecha y hora actual", "explain": "⏰ Como preguntarle a la compu '¿qué hora es?' y ella te responde con fecha y hora exacta.", "example": "date", "output": "dom mar  8 10:30:00 2026", "tipo": "comando"}, {"name": "date -s", "emoji": "⏱️", "cat": "sistema", "simple": "Cambiar la fecha del sistema", "explain": "🕰️ Como ajustar el reloj de la pared. Le dices a la computadora qué hora es realmente.", "example": "sudo date -s '2026-03-08 10:00'", "output": "(fecha del sistema actualizada)", "tipo": "comando"}, {"name": "uptime", "emoji": "⏱️", "cat": "sistema", "simple": "Ver cuánto lleva encendida la compu", "explain": "🕰️ Como preguntar '¿cuánto tiempo llevas despierta?' Te dice días y horas encendida.", "example": "uptime", "output": "10:30  up 3 days, 2:15", "tipo": "comando"}, {"name": "shutdown", "emoji": "🌙", "cat": "sistema", "simple": "Apagar la computadora", "explain": "😴 Como decirle a la compu: '¡hora de dormir!' La apaga guardando todo primero.", "example": "shutdown -h now", "output": "(apagando la computadora)", "tipo": "comando"}, {"name": "shutdown -r", "emoji": "🔄", "cat": "sistema", "simple": "Reiniciar en cierto tiempo", "explain": "⏳ Como programar la alarma para apagar y encender la compu después de X minutos.", "example": "shutdown -r +5", "output": "(reiniciará en 5 minutos)", "tipo": "comando"}, {"name": "reboot", "emoji": "🔁", "cat": "sistema", "simple": "Reiniciar la computadora", "explain": "🔁 Como apagar y volver a encender. Útil cuando algo no funciona bien.", "example": "reboot", "output": "(reiniciando...)", "tipo": "comando"}, {"name": "uname", "emoji": "💻", "cat": "sistema", "simple": "Ver información del sistema", "explain": "🏷️ Como leer la etiqueta de la computadora. Te dice qué sistema operativo y qué tipo de procesador tiene.", "example": "uname -a", "output": "Linux mi-compu 5.15.0 x86_64", "tipo": "comando"}, {"name": "hostname", "emoji": "🏷️", "cat": "sistema", "simple": "Ver el nombre de la computadora", "explain": "🏠 Como preguntar '¿cómo se llama tu casa?' Muestra el nombre que tiene la computadora en la red.", "example": "hostname", "output": "mi-laptop-genial", "tipo": "comando"}, {"name": "hostname -I", "emoji": "📡", "cat": "sistema", "simple": "Ver la IP de la computadora", "explain": "📮 Como saber la dirección postal de tu compu en la red. Muestra su número de identificación en internet.", "example": "hostname -I", "output": "192.168.1.5", "tipo": "comando"}, {"name": "df", "emoji": "💾", "cat": "sistema", "simple": "Ver el espacio en disco", "explain": "📦 Como ver cuánto espacio libre queda para guardar más juguetes. Muestra espacio del disco.", "example": "df -h", "output": "/dev/sda1  100G  40G  60G  40%", "tipo": "comando"}, {"name": "free", "emoji": "🧠", "cat": "sistema", "simple": "Ver la memoria RAM disponible", "explain": "🧠 Como ver cuántas cosas puede recordar la compu a la vez. La RAM es su memoria de trabajo.", "example": "free -h", "output": "Mem:  8.0G  3.2G  4.8G", "tipo": "comando"}, {"name": "man", "emoji": "📚", "cat": "sistema", "simple": "Ver el manual de un comando", "explain": "📗 Como abrir el libro de instrucciones. Te explica detalladamente cómo funciona cualquier comando.", "example": "man ls", "output": "(abre el manual de ls)", "tipo": "comando"}, {"name": "info", "emoji": "ℹ️", "cat": "sistema", "simple": "Ver información extendida de comandos", "explain": "📖 Como el manual pero más largo y detallado. Tiene más ejemplos y explicaciones.", "example": "info grep", "output": "(documentación detallada de grep)", "tipo": "comando"}, {"name": "alias", "emoji": "🏷️", "cat": "sistema", "simple": "Crear un apodo para un comando", "explain": "🎭 Como ponerle un apodo a tu amigo. Puedes llamar 'ver' al comando 'ls -la'.", "example": "alias ver='ls -la'", "output": "(ahora 'ver' = 'ls -la')", "tipo": "comando"}, {"name": "unalias", "emoji": "🚫", "cat": "sistema", "simple": "Eliminar un apodo creado", "explain": "🗑️ Borra el apodo que le diste a un comando. El apodo ya no funcionará.", "example": "unalias ver", "output": "(apodo 'ver' eliminado)", "tipo": "comando"}, {"name": "env", "emoji": "🌍", "cat": "sistema", "simple": "Ver las variables del entorno", "explain": "🗃️ Como ver la lista de ajustes secretos de la computadora que los programas usan.", "example": "env", "output": "HOME=/home/usuario\nLANG=es_ES.UTF-8", "tipo": "comando"}, {"name": "export", "emoji": "📤", "cat": "sistema", "simple": "Crear una variable de entorno", "explain": "📌 Como escribir en una pizarra que todos pueden ver. Crea una variable que todos los programas conocen.", "example": "export MI_NOMBRE=Carlos", "output": "(variable MI_NOMBRE creada)", "tipo": "comando"}, {"name": "printenv", "emoji": "📋", "cat": "sistema", "simple": "Ver el valor de una variable", "explain": "🔍 Como buscar un nombre en la pizarra. Te muestra el valor de una variable específica.", "example": "printenv HOME", "output": "/home/usuario", "tipo": "comando"}, {"name": "locale", "emoji": "🗺️", "cat": "sistema", "simple": "Ver configuración del idioma", "explain": "🌐 Como ver en qué idioma está configurada la computadora y cómo escribe números y fechas.", "example": "locale", "output": "LANG=es_ES.UTF-8", "tipo": "comando"}, {"name": "timedatectl", "emoji": "🕐", "cat": "sistema", "simple": "Ver y cambiar zona horaria", "explain": "🌍 Como ajustar el reloj a la zona horaria de tu país. Muy útil cuando viajas o usas servidores.", "example": "timedatectl", "output": "Local time: dom 2026-03-08\nTime zone: America/Mexico_City", "tipo": "comando"}, {"name": "cal", "emoji": "📆", "cat": "sistema", "simple": "Ver el calendario del mes", "explain": "📅 Como tener un pequeño calendario en la terminal. Te muestra el mes actual con todos los días.", "example": "cal", "output": "   Marzo 2026\nLu Ma Mi Ju Vi Sa Do", "tipo": "comando"}, {"name": "bc", "emoji": "🧮", "cat": "sistema", "simple": "Calculadora en la terminal", "explain": "🔢 Como tener una calculadora científica en la terminal. Puedes hacer sumas, restas, multiplicaciones.", "example": "echo '5 * 8' | bc", "output": "40", "tipo": "instalar"}, {"name": "sleep", "emoji": "😴", "cat": "sistema", "simple": "Hacer pausa por X segundos", "explain": "⏳ Como decirle a la terminal: 'espera N segundos antes de continuar'. Útil en scripts.", "example": "sleep 5", "output": "(espera 5 segundos)", "tipo": "comando"}, {"name": "watch", "emoji": "👁️", "cat": "sistema", "simple": "Repetir un comando cada X segundos", "explain": "🔄 Como pedir que revisen algo cada cierto tiempo. Ejecuta el mismo comando una y otra vez.", "example": "watch -n 2 date", "output": "(muestra la fecha cada 2 segundos)", "tipo": "comando"}, {"name": "at", "emoji": "⏰", "cat": "sistema", "simple": "Programar un comando para después", "explain": "📅 Como programar una alarma. Le dices: 'ejecuta esto mañana a las 3pm' y la compu lo hace sola.", "example": "at 15:00 tomorrow", "output": "(comando programado)", "tipo": "comando"}, {"name": "crontab", "emoji": "🗓️", "cat": "sistema", "simple": "Programar tareas repetitivas", "explain": "🔄 Como crear una lista de tareas automáticas. Puedes decir: 'cada lunes haz una copia de mis archivos'.", "example": "crontab -e", "output": "(editor de tareas programadas)", "tipo": "comando"}, {"name": "journalctl", "emoji": "📰", "cat": "sistema", "simple": "Ver el registro del sistema", "explain": "📓 Como el diario de la computadora. Guarda todo lo que pasó: errores, arranques, problemas.", "example": "journalctl -n 20", "output": "(últimas 20 entradas del registro)", "tipo": "comando"}, {"name": "dmesg", "emoji": "⚡", "cat": "sistema", "simple": "Ver mensajes del núcleo del sistema", "explain": "🧠 Como escuchar al cerebro de la computadora. Muestra mensajes internos del sistema operativo.", "example": "dmesg | tail", "output": "USB device connected...", "tipo": "comando"}, {"name": "lsb_release", "emoji": "🏷️", "cat": "sistema", "simple": "Ver qué distribución Linux tienes", "explain": "📋 Como leer el certificado de nacimiento de tu Linux. Te dice si es Ubuntu, Debian, etc.", "example": "lsb_release -a", "output": "Ubuntu 24.04.1 LTS", "tipo": "comando"}, {"name": "arch", "emoji": "🏗️", "cat": "sistema", "simple": "Ver la arquitectura del procesador", "explain": "🖥️ Como saber si tu procesador es de 32 o 64 bits. Importante para saber qué programas puedes instalar.", "example": "arch", "output": "x86_64", "tipo": "comando"}, {"name": "top", "emoji": "📊", "cat": "procesos", "simple": "Ver programas corriendo en tiempo real", "explain": "🏃 Como ver cuántos niños están jugando en el patio al mismo tiempo. Muestra todo en vivo.", "example": "top", "output": "(lista de procesos actualizada)", "tipo": "comando"}, {"name": "htop", "emoji": "🖥️", "cat": "procesos", "simple": "Ver procesos con colores bonitos", "explain": "🌈 Como top pero más bonito y fácil de usar. Tiene colores y es más cómodo.", "example": "htop", "output": "(vista colorida de procesos)", "tipo": "instalar"}, {"name": "ps", "emoji": "📋", "cat": "procesos", "simple": "Listar procesos activos", "explain": "📸 Como tomar una foto de todos los programas que corren en ese momento.", "example": "ps aux", "output": "USER  PID  COMMAND\nusuario  123  firefox", "tipo": "comando"}, {"name": "ps -ef", "emoji": "🔍", "cat": "procesos", "simple": "Listar todos los procesos con detalles", "explain": "🔬 Como ps pero con más detalles: quién los ejecuta, cuándo empezaron, etc.", "example": "ps -ef", "output": "usuario  123  0 10:00 firefox", "tipo": "comando"}, {"name": "kill", "emoji": "🛑", "cat": "procesos", "simple": "Cerrar un programa por su número", "explain": "🚫 Como decirle a un programa: ¡ya para! Cuando se atasca y no obedece, kill lo cierra.", "example": "kill 1234", "output": "(programa 1234 cerrado)", "tipo": "comando"}, {"name": "kill -9", "emoji": "💀", "cat": "procesos", "simple": "Forzar cierre de un programa", "explain": "⚡ El kill más fuerte. No le pregunta ni da opción: el programa muere inmediatamente.", "example": "kill -9 1234", "output": "(forzado a cerrar)", "tipo": "comando"}, {"name": "killall", "emoji": "🔫", "cat": "procesos", "simple": "Cerrar todos los procesos con ese nombre", "explain": "🎯 Como kill pero usando el nombre en vez del número. Cierra TODOS los procesos con ese nombre.", "example": "killall firefox", "output": "(todos los firefox cerrados)", "tipo": "comando"}, {"name": "pkill", "emoji": "🎯", "cat": "procesos", "simple": "Cerrar procesos por nombre o usuario", "explain": "🏹 Como killall pero más flexible. Puedes cerrar procesos de un usuario específico.", "example": "pkill -u pedro", "output": "(todos los procesos de pedro cerrados)", "tipo": "instalar"}, {"name": "nice", "emoji": "😊", "cat": "procesos", "simple": "Iniciar un proceso con prioridad ajustada", "explain": "⚖️ Como decir: 'este programa no es urgente, deja pasar a los demás primero'.", "example": "nice -n 10 programa", "output": "(programa iniciado con baja prioridad)", "tipo": "comando"}, {"name": "renice", "emoji": "🔄", "cat": "procesos", "simple": "Cambiar prioridad de un proceso", "explain": "📈 Como cambiar el turno de alguien en la fila. Subes o bajas la prioridad de un programa ya activo.", "example": "renice -n 5 -p 1234", "output": "(prioridad cambiada)", "tipo": "comando"}, {"name": "bg", "emoji": "🔙", "cat": "procesos", "simple": "Enviar proceso al fondo", "explain": "👻 Como cuando tu mamá dice 've a jugar pero sin hacer ruido'. El proceso sigue pero en segundo plano.", "example": "bg %1", "output": "[1]+ programa &", "tipo": "comando"}, {"name": "fg", "emoji": "👆", "cat": "procesos", "simple": "Traer proceso al frente", "explain": "🎤 Como llamar al niño que estaba jugando en silencio. Trae el proceso de fondo al primer plano.", "example": "fg %1", "output": "(proceso traído al frente)", "tipo": "comando"}, {"name": "jobs", "emoji": "💼", "cat": "procesos", "simple": "Ver procesos en segundo plano", "explain": "📋 Como ver la lista de niños que están jugando en silencio en el fondo. Muestra los procesos pausados.", "example": "jobs", "output": "[1]+ Running  programa &", "tipo": "comando"}, {"name": "nohup", "emoji": "🔇", "cat": "procesos", "simple": "Ejecutar sin interrupciones", "explain": "🛡️ Como poner tapones en los oídos. El proceso ignora la señal de 'cierra' y sigue corriendo.", "example": "nohup ./mi_script.sh &", "output": "(ejecutando sin interrupciones)", "tipo": "comando"}, {"name": "strace", "emoji": "🔬", "cat": "procesos", "simple": "Ver qué hace un programa por dentro", "explain": "🕵️ Como espiar qué hace un programa en secreto. Muestra cada pequeña acción que realiza.", "example": "strace ls", "output": "execve('/bin/ls'...)...", "tipo": "instalar"}, {"name": "lsof", "emoji": "📂", "cat": "procesos", "simple": "Ver archivos abiertos por procesos", "explain": "🗃️ Como saber qué libros tiene prestados cada estudiante. Muestra qué archivos usa cada proceso.", "example": "lsof -p 1234", "output": "firefox  1234  /home/usuario/.mozilla", "tipo": "instalar"}, {"name": "pgrep", "emoji": "🔎", "cat": "procesos", "simple": "Buscar el número de un proceso por nombre", "explain": "🔍 Como preguntar '¿cuál es el número de la lista de firefox?' Te da el PID del proceso.", "example": "pgrep firefox", "output": "1234\n1235", "tipo": "instalar"}, {"name": "pidof", "emoji": "🔢", "cat": "procesos", "simple": "Ver el PID de un programa", "explain": "🏷️ Como buscar el número de teléfono de alguien en la guía. Te da el número de identificación del proceso.", "example": "pidof bash", "output": "1234 5678", "tipo": "comando"}, {"name": "timeout", "emoji": "⏰", "cat": "procesos", "simple": "Ejecutar con límite de tiempo", "explain": "⏳ Como un juego con tiempo límite. Si el programa no termina en X segundos, lo cierra automático.", "example": "timeout 10 programa", "output": "(se cierra si tarda más de 10s)", "tipo": "comando"}, {"name": "time", "emoji": "⏱️", "cat": "procesos", "simple": "Medir cuánto tarda un comando", "explain": "🏁 Como cronometrar una carrera. Te dice exactamente cuánto tiempo tardó en ejecutarse el comando.", "example": "time ls -R /", "output": "real 0m2.341s\nuser 0m1.234s", "tipo": "comando"}, {"name": "wait", "emoji": "⌛", "cat": "procesos", "simple": "Esperar a que termine un proceso", "explain": "🧘 Como decir: 'no hagas nada hasta que Pedro termine su tarea'. Espera a que terminen los procesos.", "example": "wait 1234", "output": "(espera a que proceso 1234 termine)", "tipo": "comando"}, {"name": "ping", "emoji": "🏓", "cat": "red", "simple": "Ver si otra compu está disponible", "explain": "🏓 Como pegarle a una pelotita. Mandas un mensajito y esperas que te responda.", "example": "ping google.com", "output": "64 bytes de google.com: tiempo=12ms", "tipo": "comando"}, {"name": "ping -c", "emoji": "🔢", "cat": "red", "simple": "Hacer ping X veces y parar", "explain": "🎯 Como hacer exactamente 5 rebotes con la pelota y parar. ping -c 5 hace 5 intentos y ya.", "example": "ping -c 5 google.com", "output": "5 paquetes enviados, 5 recibidos", "tipo": "comando"}, {"name": "ifconfig", "emoji": "🌐", "cat": "red", "simple": "Ver la dirección de red", "explain": "🏠 Como preguntar tu dirección en internet. Muestra la IP de tu computadora.", "example": "ifconfig", "output": "eth0: inet 192.168.1.5", "tipo": "comando"}, {"name": "ip addr", "emoji": "📡", "cat": "red", "simple": "Ver direcciones de red (moderno)", "explain": "📮 La versión moderna de ifconfig. Muestra todas las IPs y interfaces de red.", "example": "ip addr", "output": "2: eth0: 192.168.1.5/24", "tipo": "comando"}, {"name": "ip route", "emoji": "🗺️", "cat": "red", "simple": "Ver las rutas de red", "explain": "🗺️ Como el mapa de caminos de internet. Muestra cómo llegan los datos a su destino.", "example": "ip route", "output": "default via 192.168.1.1\n192.168.1.0/24 dev eth0", "tipo": "comando"}, {"name": "curl", "emoji": "🌍", "cat": "red", "simple": "Descargar o visitar páginas web", "explain": "📡 Como enviar una carta a una página web. Puedes pedir información de internet sin el navegador.", "example": "curl https://ejemplo.com", "output": "[HTML] Hola desde internet! [/HTML]", "tipo": "comando"}, {"name": "curl -o", "emoji": "⬇️", "cat": "red", "simple": "Descargar y guardar con curl", "explain": "💾 Como curl pero guardas lo que descargaste en un archivo con el nombre que tú eliges.", "example": "curl -o foto.jpg https://ejemplo.com/foto.jpg", "output": "(guarda como foto.jpg)", "tipo": "comando"}, {"name": "wget", "emoji": "📥", "cat": "red", "simple": "Descargar archivos de internet", "explain": "📥 Como pedirle a alguien que te traiga algo de internet. Descarga archivos directo.", "example": "wget https://ejemplo.com/foto.jpg", "output": "foto.jpg guardado (25 KB)", "tipo": "comando"}, {"name": "wget -r", "emoji": "🕸️", "cat": "red", "simple": "Descargar un sitio completo", "explain": "🗺️ Como descargar todo un libro, no solo una página. Descarga un sitio web entero.", "example": "wget -r https://sitio.com", "output": "(descargando todo el sitio)", "tipo": "comando"}, {"name": "ssh", "emoji": "🔑", "cat": "red", "simple": "Conectarse a otra compu seguro", "explain": "🚪🔐 Como tener llave para entrar a otra computadora que está lejos. ¡Teletransportación!", "example": "ssh usuario@192.168.1.10", "output": "(conectado a compu remota)", "tipo": "comando"}, {"name": "ssh-keygen", "emoji": "🗝️", "cat": "red", "simple": "Crear llaves para SSH", "explain": "🔑 Como hacer una llave mágica que te abre las puertas de otras computadoras sin contraseña.", "example": "ssh-keygen -t rsa", "output": "(llaves generadas en ~/.ssh/)", "tipo": "comando"}, {"name": "ssh-copy-id", "emoji": "📬", "cat": "red", "simple": "Enviar tu llave a un servidor", "explain": "📮 Como mandarle una copia de tu llave a alguien para que puedas entrar después sin contraseña.", "example": "ssh-copy-id usuario@servidor", "output": "(llave enviada al servidor)", "tipo": "comando"}, {"name": "scp", "emoji": "✈️", "cat": "red", "simple": "Copiar archivos entre computadoras", "explain": "✈️ Como enviar una carta con adjunto. Manda archivos a otra computadora por internet, seguro.", "example": "scp foto.jpg usuario@servidor:/fotos/", "output": "foto.jpg transferida (100%)", "tipo": "comando"}, {"name": "rsync", "emoji": "🔄", "cat": "red", "simple": "Sincronizar archivos entre computadoras", "explain": "🔃 Como rsync inteligente: solo copia lo que cambió. Si ya tienes una copia, no vuelve a copiar todo.", "example": "rsync -av fotos/ usuario@servidor:/fotos/", "output": "(solo transfiere lo nuevo)", "tipo": "comando"}, {"name": "netstat", "emoji": "🕸️", "cat": "red", "simple": "Ver conexiones de red activas", "explain": "🕸️ Como ver todos los cables invisibles que conectan tu compu con internet.", "example": "netstat -tuln", "output": "tcp 0.0.0.0:80 LISTEN", "tipo": "comando"}, {"name": "ss", "emoji": "🔌", "cat": "red", "simple": "Ver sockets de red (moderno)", "explain": "🔌 La versión moderna de netstat. Muestra todas las conexiones de red activas.", "example": "ss -tuln", "output": "tcp LISTEN 0.0.0.0:80", "tipo": "comando"}, {"name": "nslookup", "emoji": "🔍", "cat": "red", "simple": "Buscar la IP de un sitio web", "explain": "📖 Como buscar en un directorio. Convierte 'google.com' en su dirección IP real.", "example": "nslookup google.com", "output": "Address: 142.250.80.46", "tipo": "comando"}, {"name": "dig", "emoji": "⛏️", "cat": "red", "simple": "Consultar DNS con detalles", "explain": "🔎 Como nslookup pero con muchísimos más detalles. Para expertos que quieren saber todo del DNS.", "example": "dig google.com", "output": "google.com. 300 IN A 142.250.80.46", "tipo": "instalar"}, {"name": "host", "emoji": "🏠", "cat": "red", "simple": "Ver la IP de un dominio rápido", "explain": "⚡ Como nslookup pero más simple. Solo quieres saber la IP de una página rápidamente.", "example": "host google.com", "output": "google.com has address 142.250.80.46", "tipo": "comando"}, {"name": "traceroute", "emoji": "🗺️", "cat": "red", "simple": "Ver el camino de los datos en internet", "explain": "🛤️ Como ver todas las ciudades por las que pasa tu carta antes de llegar. Muestra cada salto en internet.", "example": "traceroute google.com", "output": "1. 192.168.1.1\n2. 10.0.0.1\n3. ...google.com", "tipo": "comando"}, {"name": "mtr", "emoji": "🔭", "cat": "red", "simple": "Traceroute en tiempo real", "explain": "🌐 Combina ping y traceroute. Muestra el camino Y qué tan rápido va en cada salto, en vivo.", "example": "mtr google.com", "output": "(ruta en tiempo real con estadísticas)", "tipo": "instalar"}, {"name": "nmap", "emoji": "🗺️", "cat": "red", "simple": "Explorar puertos de una red", "explain": "🕵️ Como revisar qué puertas tiene abiertas una casa. Muestra qué servicios tiene activos una compu.", "example": "nmap 192.168.1.1", "output": "22/tcp open ssh\n80/tcp open http", "tipo": "instalar"}, {"name": "iptables", "emoji": "🛡️", "cat": "red", "simple": "Configurar el firewall", "explain": "🚧 Como poner guardias en las puertas de tu compu. Decides quién puede entrar y quién no.", "example": "sudo iptables -L", "output": "Chain INPUT (policy ACCEPT)", "tipo": "comando"}, {"name": "ufw", "emoji": "🔥", "cat": "red", "simple": "Firewall simplificado", "explain": "🛡️ Como iptables pero más fácil. Un guardia que puedes controlar con palabras simples.", "example": "sudo ufw enable", "output": "Firewall is active and enabled", "tipo": "comando"}, {"name": "nc", "emoji": "📞", "cat": "red", "simple": "Conexión de red simple", "explain": "☎️ Como un teléfono para computadoras. Puedes mandar y recibir datos entre computadoras.", "example": "nc -l 8080", "output": "(esperando conexión en puerto 8080)", "tipo": "instalar"}, {"name": "telnet", "emoji": "📺", "cat": "red", "simple": "Conectarse a un servidor básico", "explain": "📡 Como una versión antigua y sencilla de SSH. Conecta a servidores pero sin cifrado.", "example": "telnet ejemplo.com 80", "output": "(conectado al puerto 80)", "tipo": "comando"}, {"name": "ftp", "emoji": "📂", "cat": "red", "simple": "Transferir archivos por FTP", "explain": "📁 Como un camión de mudanzas por internet. Sube y baja archivos de servidores FTP.", "example": "ftp ftp.ejemplo.com", "output": "Connected to ftp.ejemplo.com", "tipo": "comando"}, {"name": "whois", "emoji": "🕵️", "cat": "red", "simple": "Ver quién es dueño de un dominio", "explain": "🏠 Como ver el registro de propietarios de una casa. Muestra quién registró un sitio web.", "example": "whois google.com", "output": "Registrar: MarkMonitor Inc.", "tipo": "comando"}, {"name": "arp", "emoji": "🔗", "cat": "red", "simple": "Ver tabla de direcciones de red local", "explain": "📋 Como la libreta de direcciones de tu red local. Muestra quién tiene qué dirección.", "example": "arp -n", "output": "192.168.1.1  08:00:27:xx:xx:xx", "tipo": "comando"}, {"name": "iwconfig", "emoji": "📶", "cat": "red", "simple": "Ver configuración del WiFi", "explain": "📡 Como ver los detalles de tu conexión inalámbrica: señal, velocidad, red conectada.", "example": "iwconfig", "output": "wlan0 ESSID:MiRed  Signal:-65dBm", "tipo": "instalar"}, {"name": "nmcli", "emoji": "🌐", "cat": "red", "simple": "Gestionar redes desde terminal", "explain": "🔌 Como el administrador de redes pero en texto. Conecta, desconecta y gestiona redes.", "example": "nmcli device status", "output": "eth0  ethernet  connected", "tipo": "instalar"}, {"name": "chmod", "emoji": "🔐", "cat": "permisos", "simple": "Cambiar permisos de un archivo", "explain": "🔑 Como decidir quién puede entrar a tu habitación. Dices quién puede leer, escribir o ejecutar.", "example": "chmod 755 mi_script.sh", "output": "(todos pueden ejecutarlo)", "tipo": "comando"}, {"name": "chmod +x", "emoji": "▶️", "cat": "permisos", "simple": "Hacer un archivo ejecutable", "explain": "🎮 Como darle un botón de 'play' a un archivo. Permite que el archivo se pueda ejecutar como programa.", "example": "chmod +x mi_programa.sh", "output": "(archivo ahora es ejecutable)", "tipo": "comando"}, {"name": "chmod -x", "emoji": "⏹️", "cat": "permisos", "simple": "Quitar permiso de ejecución", "explain": "🚫 Como quitar el botón de 'play'. El archivo ya no se puede ejecutar como programa.", "example": "chmod -x programa.sh", "output": "(ya no es ejecutable)", "tipo": "comando"}, {"name": "chmod 777", "emoji": "🔓", "cat": "permisos", "simple": "Dar todos los permisos a todos", "explain": "🚪 Como dejar la puerta abierta para todos. Cualquiera puede leer, cambiar y ejecutar el archivo.", "example": "chmod 777 archivo.txt", "output": "(permisos totales para todos)", "tipo": "comando"}, {"name": "chmod 600", "emoji": "🔒", "cat": "permisos", "simple": "Solo el dueño puede leer y escribir", "explain": "🏠 Solo el dueño del archivo puede verlo y cambiarlo. Los demás no pueden ni mirarlo.", "example": "chmod 600 secreto.txt", "output": "(solo tú puedes abrirlo)", "tipo": "comando"}, {"name": "chown", "emoji": "👤", "cat": "permisos", "simple": "Cambiar el dueño de un archivo", "explain": "🏷️ Como cambiar a quién le pertenece un juguete. Le dices a Linux: 'este archivo ahora es de María'.", "example": "chown maria archivo.txt", "output": "(archivo.txt pertenece a maria)", "tipo": "comando"}, {"name": "chown -R", "emoji": "📁", "cat": "permisos", "simple": "Cambiar dueño de carpeta y contenido", "explain": "👨‍👩‍👧 Como regalarle a María toda una caja de juguetes. Cambia el dueño de la carpeta Y todo adentro.", "example": "chown -R maria mis_archivos/", "output": "(toda la carpeta es de maria)", "tipo": "comando"}, {"name": "chgrp", "emoji": "👥", "cat": "permisos", "simple": "Cambiar el grupo de un archivo", "explain": "👨‍👩‍👧‍👦 Como cambiar a qué equipo pertenece algo. Los grupos deciden quién más puede acceder.", "example": "chgrp profesores tarea.txt", "output": "(grupo cambiado a profesores)", "tipo": "comando"}, {"name": "whoami", "emoji": "🪞", "cat": "permisos", "simple": "Ver con qué usuario estás", "explain": "🪞 Como preguntarle a un espejo '¿quién soy?' La computadora te dice tu nombre de usuario.", "example": "whoami", "output": "maria", "tipo": "comando"}, {"name": "id", "emoji": "🪪", "cat": "permisos", "simple": "Ver tu ID de usuario y grupos", "explain": "🪪 Como ver tu credencial completa. Muestra tu número de usuario y a qué grupos perteneces.", "example": "id", "output": "uid=1000(maria) gid=1000(maria) grupos=1000,27(sudo)", "tipo": "comando"}, {"name": "groups", "emoji": "👥", "cat": "permisos", "simple": "Ver los grupos a los que perteneces", "explain": "👨‍👩‍👧‍👦 Como ver en qué equipos de la escuela estás. Los grupos deciden qué puedes hacer.", "example": "groups", "output": "maria sudo audio video", "tipo": "comando"}, {"name": "passwd", "emoji": "🔒", "cat": "permisos", "simple": "Cambiar tu contraseña", "explain": "🔑 Como cambiar la clave de tu diario. Te pide la contraseña antigua y pones una nueva.", "example": "passwd", "output": "(te pide la nueva contraseña)", "tipo": "comando"}, {"name": "useradd", "emoji": "➕", "cat": "permisos", "simple": "Crear un usuario nuevo", "explain": "🧑‍💻 Como crear un perfil nuevo. Le das un nombre y ya puede usar la computadora.", "example": "sudo useradd pedro", "output": "(usuario pedro creado)", "tipo": "comando"}, {"name": "useradd -m", "emoji": "🏠", "cat": "permisos", "simple": "Crear usuario con carpeta personal", "explain": "🏠 Como crear un usuario Y hacerle su propia habitación (carpeta /home/nombre).", "example": "sudo useradd -m pedro", "output": "(pedro creado con /home/pedro)", "tipo": "comando"}, {"name": "userdel", "emoji": "➖", "cat": "permisos", "simple": "Eliminar un usuario", "explain": "🗑️ Como borrar el perfil de alguien. Esa persona ya no podrá iniciar sesión.", "example": "sudo userdel pedro", "output": "(usuario pedro eliminado)", "tipo": "comando"}, {"name": "usermod", "emoji": "✏️", "cat": "permisos", "simple": "Modificar un usuario existente", "explain": "📝 Como editar el perfil de alguien. Puedes cambiar su nombre, grupo, carpeta personal, etc.", "example": "sudo usermod -aG sudo pedro", "output": "(pedro añadido al grupo sudo)", "tipo": "comando"}, {"name": "groupadd", "emoji": "👥", "cat": "permisos", "simple": "Crear un grupo nuevo", "explain": "🏫 Como crear un equipo nuevo en la escuela. Después puedes meter personas en ese grupo.", "example": "sudo groupadd profesores", "output": "(grupo profesores creado)", "tipo": "comando"}, {"name": "groupdel", "emoji": "🗑️", "cat": "permisos", "simple": "Eliminar un grupo", "explain": "🗑️ Como disolver un equipo. El grupo desaparece del sistema.", "example": "sudo groupdel profesores", "output": "(grupo profesores eliminado)", "tipo": "comando"}, {"name": "visudo", "emoji": "📜", "cat": "permisos", "simple": "Editar permisos de administrador", "explain": "👑 Como editar la lista de quién tiene superpoderes. Muy importante para la seguridad del sistema.", "example": "sudo visudo", "output": "(editor de permisos sudo)", "tipo": "comando"}, {"name": "last", "emoji": "📅", "cat": "permisos", "simple": "Ver últimos inicios de sesión", "explain": "📓 Como ver el libro de visitas. Muestra quién entró a la computadora y cuándo.", "example": "last", "output": "maria  tty1  dom mar 8 10:00", "tipo": "comando"}, {"name": "lastlog", "emoji": "🔍", "cat": "permisos", "simple": "Ver último acceso de cada usuario", "explain": "🗂️ Como ver cuándo entró por última vez cada persona. Útil para saber si alguien entró sin permiso.", "example": "lastlog", "output": "maria  tty1  dom mar 8 10:00\npedro  Never", "tipo": "comando"}, {"name": "w", "emoji": "👋", "cat": "permisos", "simple": "Ver quién está conectado ahora", "explain": "🧑‍🤝‍🧑 Como asomarte a ver quién está en la sala. Muestra todos los usuarios conectados en este momento.", "example": "w", "output": "maria  tty1  10:00  top", "tipo": "comando"}, {"name": "who", "emoji": "👤", "cat": "permisos", "simple": "Ver usuarios conectados (simple)", "explain": "📋 Como who pero más simple. Solo muestra nombre, terminal y hora de entrada.", "example": "who", "output": "maria   tty1   2026-03-08 10:00", "tipo": "comando"}, {"name": "su -", "emoji": "🦸", "cat": "permisos", "simple": "Cambiar a root completamente", "explain": "🦸‍♂️ Como ponerse el traje de superhéroe completo. Te conviertes totalmente en el administrador.", "example": "su -", "output": "(eres root ahora)", "tipo": "comando"}, {"name": "find", "emoji": "🔎", "cat": "busqueda", "simple": "Buscar archivos por nombre", "explain": "🕵️ Como buscar un juguete perdido revisando cada cajón. Encuentra archivos en todas las carpetas.", "example": "find . -name '*.txt'", "output": "./notas.txt\n./docs/tarea.txt", "tipo": "comando"}, {"name": "find -type f", "emoji": "📄", "cat": "busqueda", "simple": "Buscar solo archivos", "explain": "🔍 Como buscar pero solo buscas papeles, no cajas. Solo encuentra archivos, no carpetas.", "example": "find . -type f", "output": "./nota.txt\n./foto.jpg", "tipo": "comando"}, {"name": "find -type d", "emoji": "📁", "cat": "busqueda", "simple": "Buscar solo carpetas", "explain": "📦 Como buscar solo cajas, no papeles. Solo encuentra carpetas, no archivos.", "example": "find . -type d", "output": "./fotos\n./musica", "tipo": "comando"}, {"name": "find -size", "emoji": "📏", "cat": "busqueda", "simple": "Buscar archivos por tamaño", "explain": "⚖️ Como buscar juguetes grandes. Encuentra archivos que sean más grandes o más pequeños que X.", "example": "find . -size +1M", "output": "./video_grande.mp4", "tipo": "comando"}, {"name": "find -mtime", "emoji": "📅", "cat": "busqueda", "simple": "Buscar archivos por fecha", "explain": "🗓️ Como buscar cosas que compraste esta semana. Encuentra archivos modificados hace X días.", "example": "find . -mtime -7", "output": "(archivos de los últimos 7 días)", "tipo": "comando"}, {"name": "grep", "emoji": "🧲", "cat": "busqueda", "simple": "Buscar texto dentro de archivos", "explain": "🔍 Como buscar una palabra en un libro. Grep revisa el archivo y muestra las líneas donde aparece.", "example": "grep 'hola' mensaje.txt", "output": "línea 3: hola amigo!", "tipo": "comando"}, {"name": "grep -i", "emoji": "🔡", "cat": "busqueda", "simple": "Buscar sin importar mayúsculas", "explain": "🔠 Como buscar 'Hola', 'hola' y 'HOLA' al mismo tiempo. No le importa si es mayúscula o minúscula.", "example": "grep -i 'hola' texto.txt", "output": "Hola mundo\nhola amigo\nHOLA!", "tipo": "comando"}, {"name": "grep -r", "emoji": "🌳", "cat": "busqueda", "simple": "Buscar en todas las carpetas", "explain": "🕵️ Como grep pero busca en TODOS los archivos de TODAS las carpetas a la vez.", "example": "grep -r 'error' /var/log/", "output": "syslog:Error encontrado", "tipo": "comando"}, {"name": "grep -n", "emoji": "🔢", "cat": "busqueda", "simple": "Buscar mostrando número de línea", "explain": "📋 Como grep pero también te dice en qué renglón exacto está la palabra que buscas.", "example": "grep -n 'error' log.txt", "output": "15: error crítico detectado", "tipo": "comando"}, {"name": "grep -v", "emoji": "🚫", "cat": "busqueda", "simple": "Mostrar líneas que NO contienen algo", "explain": "↩️ Al revés del grep normal. Muestra todo EXCEPTO las líneas que tienen la palabra.", "example": "grep -v 'error' log.txt", "output": "(todas las líneas sin 'error')", "tipo": "comando"}, {"name": "grep -c", "emoji": "🔢", "cat": "busqueda", "simple": "Contar cuántas veces aparece algo", "explain": "🧮 Como grep pero solo te dice el número: '¿cuántas veces aparece esta palabra?'", "example": "grep -c 'error' log.txt", "output": "5", "tipo": "comando"}, {"name": "locate", "emoji": "📡", "cat": "busqueda", "simple": "Buscar archivos súper rápido", "explain": "⚡ Como tener un mapa del tesoro ya hecho. Busca en una lista guardada, mucho más rápido.", "example": "locate foto.jpg", "output": "/home/usuario/fotos/foto.jpg", "tipo": "instalar"}, {"name": "updatedb", "emoji": "🔄", "cat": "busqueda", "simple": "Actualizar la base de datos de locate", "explain": "🗺️ Como actualizar el mapa del tesoro. Escanea el disco para que locate tenga info fresca.", "example": "sudo updatedb", "output": "(base de datos actualizada)", "tipo": "instalar"}, {"name": "which", "emoji": "📍", "cat": "busqueda", "simple": "Ver dónde está instalado un programa", "explain": "🗺️ Como preguntar '¿dónde vive ese programa?' Te dice en qué carpeta está guardado.", "example": "which python", "output": "/usr/bin/python", "tipo": "comando"}, {"name": "whereis", "emoji": "🗺️", "cat": "busqueda", "simple": "Ver dónde está un programa y su manual", "explain": "🔍 Como whereis pero más completo: te dice dónde está el programa Y dónde están sus manuales.", "example": "whereis ls", "output": "ls: /bin/ls /usr/share/man/man1/ls.1.gz", "tipo": "comando"}, {"name": "sort", "emoji": "🔡", "cat": "busqueda", "simple": "Ordenar líneas de un archivo", "explain": "🔤 Como ordenar cromos del abecedario. Pone una lista desordenada en orden.", "example": "sort nombres.txt", "output": "Ana\nCarlos\nMaria\nPedro", "tipo": "comando"}, {"name": "sort -r", "emoji": "🔃", "cat": "busqueda", "simple": "Ordenar al revés (Z a A)", "explain": "🔽 Como sort pero al revés. Si normalmente va de A a Z, este va de Z a A.", "example": "sort -r nombres.txt", "output": "Pedro\nMaria\nCarlos\nAna", "tipo": "comando"}, {"name": "sort -n", "emoji": "🔢", "cat": "busqueda", "simple": "Ordenar números correctamente", "explain": "🔢 Para ordenar números de menor a mayor. Sin esto, '10' podría ordenarse antes que '9'.", "example": "sort -n numeros.txt", "output": "1\n2\n9\n10\n100", "tipo": "comando"}, {"name": "uniq", "emoji": "🎯", "cat": "busqueda", "simple": "Eliminar líneas repetidas", "explain": "🧹 Como quitar duplicados de una lista. Si 'hola' aparece 3 veces, lo deja solo una.", "example": "sort lista.txt | uniq", "output": "Ana\nCarlos\nMaria", "tipo": "comando"}, {"name": "uniq -c", "emoji": "🔢", "cat": "busqueda", "simple": "Contar repeticiones de cada línea", "explain": "🧮 Como uniq pero también te dice cuántas veces se repetía cada cosa.", "example": "sort lista.txt | uniq -c", "output": "3 Ana\n1 Carlos\n2 Maria", "tipo": "comando"}, {"name": "cut", "emoji": "✂️", "cat": "busqueda", "simple": "Cortar partes de texto", "explain": "✂️ Como cortar solo una columna de una tabla. Puedes tomar solo cierta parte de cada línea.", "example": "cut -d',' -f1 lista.csv", "output": "nombre\nAna\nCarlos", "tipo": "comando"}, {"name": "sed", "emoji": "🔄", "cat": "busqueda", "simple": "Reemplazar texto en archivos", "explain": "✏️ El corrector automático. Busca una palabra y la cambia por otra en todo el archivo.", "example": "sed 's/gato/perro/g' animales.txt", "output": "Mi perro es bonito", "tipo": "comando"}, {"name": "pipe |", "emoji": "🔗", "cat": "busqueda", "simple": "Conectar comandos en cadena", "explain": "🔗 Como un embudo entre dos vasos. La salida del primer comando entra al segundo.", "example": "ls | grep '.txt'", "output": "notas.txt\ntarea.txt", "tipo": "sintaxis"}, {"name": "xargs", "emoji": "➡️", "cat": "busqueda", "simple": "Pasar resultados como argumentos", "explain": "🤲 Como llevar los resultados de un comando y dárselos a otro. Une comandos de forma poderosa.", "example": "find . -name '*.txt' | xargs rm", "output": "(borra todos los .txt encontrados)", "tipo": "comando"}, {"name": "nano", "emoji": "✍️", "cat": "texto", "simple": "Editor de texto simple", "explain": "📝 Como abrir un cuaderno para escribir. Puedes escribir, corregir y guardar.", "example": "nano mi_historia.txt", "output": "(se abre el editor nano)", "tipo": "comando"}, {"name": "vim", "emoji": "⚡", "cat": "texto", "simple": "Editor de texto avanzado", "explain": "🥋 El editor de los profesionales. Muy poderoso pero un poco difícil al principio.", "example": "vim mi_archivo.txt", "output": "(se abre vim)", "tipo": "instalar"}, {"name": "vi", "emoji": "📝", "cat": "texto", "simple": "Editor de texto clásico", "explain": "🏛️ El abuelo de vim. Viene en todos los sistemas Linux, siempre disponible.", "example": "vi config.txt", "output": "(se abre vi)", "tipo": "comando"}, {"name": "gedit", "emoji": "🖊️", "cat": "texto", "simple": "Editor de texto gráfico", "explain": "🪟 Como el Bloc de Notas de Windows pero en Linux. Tiene ventana y botones.", "example": "gedit nota.txt", "output": "(se abre gedit con ventana)", "tipo": "instalar"}, {"name": "head", "emoji": "🎩", "cat": "texto", "simple": "Ver las primeras líneas", "explain": "👆 Como leer solo las primeras páginas. Te muestra el principio del archivo.", "example": "head -5 cuento.txt", "output": "Había una vez...", "tipo": "comando"}, {"name": "tail", "emoji": "🦊", "cat": "texto", "simple": "Ver las últimas líneas", "explain": "👇 Como leer solo el final. Te muestra las últimas líneas del archivo.", "example": "tail -5 cuento.txt", "output": "...vivieron felices.", "tipo": "comando"}, {"name": "tail -f", "emoji": "📺", "cat": "texto", "simple": "Ver archivo en tiempo real", "explain": "📡 Como ver un canal de noticias en vivo. Muestra el archivo y se actualiza cuando cambia.", "example": "tail -f /var/log/syslog", "output": "(muestra nuevas líneas al aparecer)", "tipo": "comando"}, {"name": "more", "emoji": "📄", "cat": "texto", "simple": "Ver archivo página por página", "explain": "📖 Como hojear un libro de a una página. Muestra el archivo poco a poco para no abrumarte.", "example": "more manual_largo.txt", "output": "(página 1 de 10 - presiona espacio)", "tipo": "comando"}, {"name": "less", "emoji": "📚", "cat": "texto", "simple": "Ver archivo con navegación", "explain": "📚 Como more pero mejor. Puedes ir hacia atrás también, no solo hacia adelante.", "example": "less archivo_largo.txt", "output": "(navega con flechas)", "tipo": "comando"}, {"name": "tr", "emoji": "🔄", "cat": "texto", "simple": "Reemplazar caracteres", "explain": "🔡 Como cambiar todas las letras de un tipo. Por ejemplo: convertir minúsculas en mayúsculas.", "example": "echo 'hola' | tr 'a-z' 'A-Z'", "output": "HOLA", "tipo": "comando"}, {"name": "tr -d", "emoji": "🗑️", "cat": "texto", "simple": "Eliminar caracteres específicos", "explain": "✂️ Como borrar todas las comas de un texto. Elimina cada aparición del carácter que dices.", "example": "echo 'h,o,l,a' | tr -d ','", "output": "hola", "tipo": "comando"}, {"name": "fold", "emoji": "📐", "cat": "texto", "simple": "Limitar el ancho de líneas", "explain": "📏 Como doblar una hoja larga para que quepa. Corta las líneas largas a X caracteres.", "example": "fold -w 40 texto.txt", "output": "(líneas de máximo 40 caracteres)", "tipo": "instalar"}, {"name": "fmt", "emoji": "🖨️", "cat": "texto", "simple": "Formatear texto en párrafos", "explain": "📄 Como darle formato bonito a un texto. Ordena y acomoda el texto en párrafos bien formados.", "example": "fmt -w 60 texto.txt", "output": "(texto reformateado a 60 chars)", "tipo": "instalar"}, {"name": "column", "emoji": "📊", "cat": "texto", "simple": "Mostrar datos en columnas alineadas", "explain": "📋 Como organizar información en una tabla con columnas bien alineadas.", "example": "column -t datos.txt", "output": "nombre  edad  ciudad\nAna     25    Madrid", "tipo": "instalar"}, {"name": "rev", "emoji": "🔄", "cat": "texto", "simple": "Invertir texto al revés", "explain": "🔁 Como leer al revés. Toma cada línea y la voltea: 'hola' se convierte en 'aloh'.", "example": "echo 'hola' | rev", "output": "aloh", "tipo": "comando"}, {"name": "base64", "emoji": "🔐", "cat": "texto", "simple": "Codificar texto en base64", "explain": "🔒 Como escribir en código secreto. Convierte texto normal en una cadena de letras y números.", "example": "echo 'hola' | base64", "output": "aG9sYQ==", "tipo": "comando"}, {"name": "base64 -d", "emoji": "🔓", "cat": "texto", "simple": "Decodificar texto base64", "explain": "🔑 Como descifrar el código secreto. Convierte base64 de nuevo a texto normal.", "example": "echo 'aG9sYQ==' | base64 -d", "output": "hola", "tipo": "comando"}, {"name": "strings", "emoji": "🧵", "cat": "texto", "simple": "Extraer texto de archivos binarios", "explain": "🔍 Como buscar palabras legibles en un archivo que parece jeroglífico. Extrae texto de programas.", "example": "strings programa_binario", "output": "Hola Mundo\nError: archivo no encontrado", "tipo": "instalar"}, {"name": "iconv", "emoji": "🔤", "cat": "texto", "simple": "Convertir codificación de texto", "explain": "🌐 Como traducir el idioma en que está escrito un archivo. Convierte entre UTF-8, ISO-8859, etc.", "example": "iconv -f ISO-8859-1 -t UTF-8 archivo.txt", "output": "(convierte la codificación)", "tipo": "instalar"}, {"name": "dos2unix", "emoji": "🔄", "cat": "texto", "simple": "Convertir formato Windows a Linux", "explain": "🖥️ Los archivos de Windows tienen saltos de línea diferentes. Este los corrige para Linux.", "example": "dos2unix archivo_windows.txt", "output": "(convertido a formato Unix)", "tipo": "instalar"}, {"name": "unix2dos", "emoji": "🔄", "cat": "texto", "simple": "Convertir formato Linux a Windows", "explain": "🪟 Al revés de dos2unix. Convierte archivos de Linux para que Windows los entienda bien.", "example": "unix2dos mi_archivo.txt", "output": "(convertido a formato Windows)", "tipo": "instalar"}, {"name": "expand", "emoji": "⬛", "cat": "texto", "simple": "Convertir tabs en espacios", "explain": "📐 Como reemplazar tabulaciones con espacios. Útil para que el texto se vea igual en todos lados.", "example": "expand archivo.txt", "output": "(tabs reemplazados por espacios)", "tipo": "comando"}, {"name": "unexpand", "emoji": "↔️", "cat": "texto", "simple": "Convertir espacios en tabs", "explain": "📐 Al revés de expand. Convierte espacios de vuelta en tabulaciones.", "example": "unexpand archivo.txt", "output": "(espacios reemplazados por tabs)", "tipo": "comando"}, {"name": "paste", "emoji": "📋", "cat": "texto", "simple": "Unir líneas de dos archivos", "explain": "🧩 Como juntar dos listas lado a lado. Toma líneas de dos archivos y las pone en columnas.", "example": "paste nombres.txt edades.txt", "output": "Ana  25\nCarlos  30", "tipo": "instalar"}, {"name": "join", "emoji": "🔗", "cat": "texto", "simple": "Unir archivos por columna común", "explain": "🧩 Como unir dos tablas que tienen una columna en común. Una especie de JOIN de base de datos.", "example": "join nombres.txt salarios.txt", "output": "Ana 25 50000", "tipo": "instalar"}, {"name": "comm", "emoji": "🔍", "cat": "texto", "simple": "Comparar dos archivos ordenados", "explain": "📊 Como buscar qué tienen en común dos listas. Muestra lo que está solo en A, solo en B, y en ambos.", "example": "comm lista1.txt lista2.txt", "output": "(solo en 1)  (solo en 2)  (ambos)", "tipo": "instalar"}, {"name": "apt install", "emoji": "📥", "cat": "paquetes", "simple": "Instalar un programa (Ubuntu/Debian)", "explain": "🛒 Como ir a la tienda de apps. Le dices qué quieres instalar y se descarga solo.", "example": "sudo apt install firefox", "output": "(instalando firefox...)", "tipo": "comando"}, {"name": "apt remove", "emoji": "🗑️", "cat": "paquetes", "simple": "Desinstalar un programa", "explain": "🗑️ Como devolver un juguete a la tienda. Borra el programa de tu computadora.", "example": "sudo apt remove firefox", "output": "(desinstalando firefox...)", "tipo": "comando"}, {"name": "apt update", "emoji": "🔄", "cat": "paquetes", "simple": "Actualizar lista de programas", "explain": "📰 Como actualizar el catálogo de la tienda. Descarga la lista más reciente de programas disponibles.", "example": "sudo apt update", "output": "(actualizando lista de paquetes)", "tipo": "comando"}, {"name": "apt upgrade", "emoji": "⬆️", "cat": "paquetes", "simple": "Actualizar todos los programas", "explain": "🆕 Como actualizar todos tus juguetes a las versiones más nuevas. Actualiza todo lo instalado.", "example": "sudo apt upgrade", "output": "(actualizando todos los paquetes)", "tipo": "comando"}, {"name": "apt search", "emoji": "🔍", "cat": "paquetes", "simple": "Buscar un programa disponible", "explain": "🔍 Como buscar en el catálogo de la tienda. Encuentra programas que puedes instalar.", "example": "apt search editor de video", "output": "kdenlive - editor de video...", "tipo": "comando"}, {"name": "apt show", "emoji": "📋", "cat": "paquetes", "simple": "Ver información de un paquete", "explain": "🏷️ Como leer la etiqueta de un producto en la tienda. Muestra detalles de un programa.", "example": "apt show firefox", "output": "Versión: 124.0\nDescripción: Navegador web", "tipo": "comando"}, {"name": "apt autoremove", "emoji": "🧹", "cat": "paquetes", "simple": "Eliminar paquetes innecesarios", "explain": "🧽 Como tirar cajas vacías que ya no necesitas. Borra programas que se instalaron solos y ya no hacen falta.", "example": "sudo apt autoremove", "output": "(limpiando paquetes huérfanos)", "tipo": "comando"}, {"name": "apt-get", "emoji": "📦", "cat": "paquetes", "simple": "Gestor de paquetes clásico", "explain": "🏪 La versión antigua de apt. Hace lo mismo pero con sintaxis un poco diferente.", "example": "sudo apt-get install nano", "output": "(instalando nano...)", "tipo": "comando"}, {"name": "dpkg -i", "emoji": "📦", "cat": "paquetes", "simple": "Instalar paquete .deb manual", "explain": "🧩 Como instalar un juguete que compraste por separado. Instala un archivo .deb descargado.", "example": "sudo dpkg -i programa.deb", "output": "(instalando programa.deb)", "tipo": "comando"}, {"name": "dpkg -l", "emoji": "📋", "cat": "paquetes", "simple": "Listar programas instalados", "explain": "🗂️ Como el inventario de lo que tienes instalado. Lista todos los paquetes en el sistema.", "example": "dpkg -l", "output": "ii  firefox  124.0  Navegador web", "tipo": "comando"}, {"name": "dpkg -r", "emoji": "🗑️", "cat": "paquetes", "simple": "Desinstalar paquete con dpkg", "explain": "🗑️ Como dpkg pero para desinstalar. Quita el programa del sistema.", "example": "sudo dpkg -r firefox", "output": "(firefox desinstalado)", "tipo": "comando"}, {"name": "snap install", "emoji": "📦", "cat": "paquetes", "simple": "Instalar programa snap", "explain": "🫙 Como instalar desde otra tienda de apps. Snap es un formato de paquete más moderno.", "example": "sudo snap install vscode", "output": "(instalando vscode desde snap)", "tipo": "instalar"}, {"name": "snap list", "emoji": "📋", "cat": "paquetes", "simple": "Listar programas snap instalados", "explain": "📋 Como ver qué tienes instalado de la tienda Snap.", "example": "snap list", "output": "vscode  1.87  ...", "tipo": "instalar"}, {"name": "snap remove", "emoji": "🗑️", "cat": "paquetes", "simple": "Desinstalar programa snap", "explain": "🗑️ Como devolver un programa de snap. Lo desinstala del sistema.", "example": "sudo snap remove vscode", "output": "(vscode eliminado)", "tipo": "instalar"}, {"name": "flatpak install", "emoji": "📦", "cat": "paquetes", "simple": "Instalar programa flatpak", "explain": "📦 Otro formato de paquete moderno, como Snap pero diferente. Muy popular en Linux.", "example": "flatpak install flathub vlc", "output": "(instalando VLC flatpak)", "tipo": "instalar"}, {"name": "pip install", "emoji": "🐍", "cat": "paquetes", "simple": "Instalar librería de Python", "explain": "🐍 Como instalar un módulo para Python. Descarga e instala herramientas para programar en Python.", "example": "pip install requests", "output": "(instalando requests para Python)", "tipo": "instalar"}, {"name": "pip list", "emoji": "📋", "cat": "paquetes", "simple": "Ver librerías Python instaladas", "explain": "📋 Como ver qué herramientas de Python tienes. Lista todos los módulos instalados.", "example": "pip list", "output": "requests  2.31.0\nnumpy  1.26.0", "tipo": "instalar"}, {"name": "npm install", "emoji": "🟢", "cat": "paquetes", "simple": "Instalar paquete Node.js", "explain": "🟢 Como instalar herramientas para programar en JavaScript. Descarga el paquete que necesitas.", "example": "npm install express", "output": "(instalando express para Node.js)", "tipo": "instalar"}, {"name": "npm -g install", "emoji": "🌍", "cat": "paquetes", "simple": "Instalar paquete Node.js global", "explain": "🌐 Como npm install pero disponible para todos los proyectos, no solo uno.", "example": "npm install -g nodemon", "output": "(nodemon instalado globalmente)", "tipo": "instalar"}, {"name": "rpm -i", "emoji": "📦", "cat": "paquetes", "simple": "Instalar paquete RPM (Red Hat/Fedora)", "explain": "🎩 Como dpkg pero para sistemas como Fedora o Red Hat. Instala archivos .rpm.", "example": "sudo rpm -i programa.rpm", "output": "(instalando programa.rpm)", "tipo": "instalar"}, {"name": "yum install", "emoji": "📥", "cat": "paquetes", "simple": "Instalar programa (CentOS/RHEL)", "explain": "🛒 Como apt pero para sistemas Red Hat y CentOS. La tienda de apps de esos sistemas.", "example": "sudo yum install nginx", "output": "(instalando nginx...)", "tipo": "instalar"}, {"name": "dnf install", "emoji": "📥", "cat": "paquetes", "simple": "Instalar programa (Fedora)", "explain": "🛒 La tienda de apps de Fedora. Más moderno que yum, con mejores mensajes.", "example": "sudo dnf install vlc", "output": "(instalando vlc en Fedora)", "tipo": "instalar"}, {"name": "pacman -S", "emoji": "👾", "cat": "paquetes", "simple": "Instalar programa (Arch Linux)", "explain": "👾 La tienda de apps de Arch Linux. ¡El gestor de paquetes más famoso por su nombre divertido!", "example": "sudo pacman -S firefox", "output": "(instalando firefox en Arch)", "tipo": "instalar"}, {"name": "lscpu", "emoji": "🧠", "cat": "hardware", "simple": "Ver información del procesador", "explain": "🖥️ Como leer el certificado del cerebro de tu compu. Muestra velocidad, núcleos, etc.", "example": "lscpu", "output": "Architecture: x86_64\nCPU: Intel Core i5\nCores: 4", "tipo": "comando"}, {"name": "lsmem", "emoji": "💾", "cat": "hardware", "simple": "Ver información de la memoria RAM", "explain": "🧠 Como ver las especificaciones de la memoria de tu compu. Cuánta RAM y cómo está organizada.", "example": "lsmem", "output": "Total online: 8G", "tipo": "comando"}, {"name": "lspci", "emoji": "🔌", "cat": "hardware", "simple": "Ver dispositivos PCI conectados", "explain": "🔌 Como ver qué tarjetas están enchufadas dentro de la computadora: gráfica, sonido, red.", "example": "lspci", "output": "00:02.0 VGA: Intel HD Graphics\n02:00.0 Network: Realtek", "tipo": "comando"}, {"name": "lsusb", "emoji": "🔌", "cat": "hardware", "simple": "Ver dispositivos USB conectados", "explain": "🖱️ Como ver qué tienes enchufado en los puertos USB: ratón, teclado, memoria, etc.", "example": "lsusb", "output": "Bus 002 Device 003: Kingston DataTraveler\nBus 001 Device 002: Logitech Mouse", "tipo": "comando"}, {"name": "lsblk", "emoji": "💿", "cat": "hardware", "simple": "Ver discos y particiones", "explain": "💿 Como ver todos los discos de la computadora y cómo están divididos en partes.", "example": "lsblk", "output": "sda  500G\n├─sda1  100G /boot\n└─sda2  400G /", "tipo": "comando"}, {"name": "fdisk -l", "emoji": "💾", "cat": "hardware", "simple": "Ver particiones del disco", "explain": "📊 Como ver el mapa detallado de cómo está dividido el disco duro.", "example": "sudo fdisk -l", "output": "/dev/sda1  2048  204800  Windows\n/dev/sda2  204801  ...  Linux", "tipo": "comando"}, {"name": "blkid", "emoji": "🔖", "cat": "hardware", "simple": "Ver IDs de particiones", "explain": "🏷️ Como el número de serie de cada partición del disco. Útil para saber cuál es cuál.", "example": "sudo blkid", "output": "/dev/sda1: UUID='abc-123' TYPE='ext4'", "tipo": "comando"}, {"name": "hdparm", "emoji": "📊", "cat": "hardware", "simple": "Ver y ajustar parámetros del disco", "explain": "⚙️ Como el panel de control del disco duro. Puedes ver su velocidad y ajustar configuraciones.", "example": "sudo hdparm -I /dev/sda", "output": "Model: Samsung SSD 870\nCapacity: 500GB", "tipo": "instalar"}, {"name": "smartctl", "emoji": "🩺", "cat": "hardware", "simple": "Revisar salud del disco duro", "explain": "🏥 Como llevar el disco al doctor. Revisa si está sano o si pronto va a fallar.", "example": "sudo smartctl -a /dev/sda", "output": "SMART overall-health: PASSED", "tipo": "instalar"}, {"name": "sensors", "emoji": "🌡️", "cat": "hardware", "simple": "Ver temperatura del procesador", "explain": "🌡️ Como ponerle termómetro a la computadora. Muestra la temperatura de la CPU y otros componentes.", "example": "sensors", "output": "Core 0: +45.0°C\nCore 1: +43.0°C", "tipo": "instalar"}, {"name": "nvidia-smi", "emoji": "🎮", "cat": "hardware", "simple": "Ver información de la GPU Nvidia", "explain": "🎮 Como ver el tablero de control de tu tarjeta gráfica Nvidia. Muestra temperatura, uso, memoria.", "example": "nvidia-smi", "output": "GPU Temp: 62C | Memory: 4GB/8GB", "tipo": "instalar"}, {"name": "dmidecode", "emoji": "🔍", "cat": "hardware", "simple": "Ver información detallada del hardware", "explain": "🔬 Como radiografiar la computadora. Muestra información muy detallada de cada componente.", "example": "sudo dmidecode -t memory", "output": "Memory Device\n  Size: 8192 MB", "tipo": "instalar"}, {"name": "inxi", "emoji": "📊", "cat": "hardware", "simple": "Ver resumen del hardware", "explain": "📋 Como el resumen médico de tu computadora. Muestra todo el hardware en un formato bonito.", "example": "inxi -F", "output": "CPU: Intel i5  RAM: 8GB  HDD: 500GB", "tipo": "instalar"}, {"name": "hwinfo", "emoji": "🖥️", "cat": "hardware", "simple": "Ver información completa del hardware", "explain": "📖 Como el manual completo de tu computadora. Muestra absolutamente todo el hardware.", "example": "hwinfo --short", "output": "(resumen de todo el hardware)", "tipo": "instalar"}, {"name": "modinfo", "emoji": "🔌", "cat": "hardware", "simple": "Ver información de un módulo/driver", "explain": "📋 Como leer la ficha técnica de un driver. Muestra de dónde viene y qué hace.", "example": "modinfo nvidia", "output": "filename: /lib/modules/.../nvidia.ko", "tipo": "comando"}, {"name": "lsmod", "emoji": "📦", "cat": "hardware", "simple": "Ver drivers del sistema cargados", "explain": "🔌 Como ver qué drivers están activos. Lista todos los módulos que el sistema está usando.", "example": "lsmod", "output": "Module        Size  Used\nnvidia  5000000  1", "tipo": "comando"}, {"name": "modprobe", "emoji": "🔌", "cat": "hardware", "simple": "Cargar un driver del sistema", "explain": "🔌 Como conectar un módulo al sistema. Activa un driver para que el hardware funcione.", "example": "sudo modprobe nvidia", "output": "(driver nvidia cargado)", "tipo": "instalar"}, {"name": "rmmod", "emoji": "🔌", "cat": "hardware", "simple": "Descargar un driver del sistema", "explain": "🔌 Como desconectar un módulo. Desactiva un driver del sistema.", "example": "sudo rmmod nvidia", "output": "(driver nvidia descargado)", "tipo": "instalar"}, {"name": "iwlist", "emoji": "📶", "cat": "hardware", "simple": "Buscar redes WiFi disponibles", "explain": "📡 Como el escáner de WiFi. Busca y lista todas las redes inalámbricas cercanas.", "example": "iwlist wlan0 scan", "output": "ESSID: MiRed\nSignal: -65dBm", "tipo": "instalar"}, {"name": "rfkill", "emoji": "📡", "cat": "hardware", "simple": "Activar/desactivar WiFi o Bluetooth", "explain": "📵 Como el interruptor del WiFi. Puedes encender o apagar la radio inalámbrica.", "example": "rfkill list", "output": "0: phy0: Wireless LAN\n  Soft blocked: no", "tipo": "instalar"}, {"name": "bash", "emoji": "🐚", "cat": "shell", "simple": "Iniciar una nueva sesión bash", "explain": "🐚 Como abrir otra terminal dentro de la terminal. Bash es el lenguaje que habla Linux.", "example": "bash", "output": "(nueva sesión bash iniciada)", "tipo": "comando"}, {"name": "sh", "emoji": "📜", "cat": "shell", "simple": "Ejecutar un script de shell", "explain": "📜 Como decirle a Linux: 'sigue estas instrucciones del archivo'. Ejecuta un script.", "example": "sh mi_script.sh", "output": "(ejecuta mi_script.sh)", "tipo": "comando"}, {"name": "./script.sh", "emoji": "▶️", "cat": "shell", "simple": "Ejecutar un script directamente", "explain": "▶️ Como dar 'play' a un script. El punto y la barra dicen: 'está aquí mismo, ejecutalo'.", "example": "./mi_programa.sh", "output": "(programa ejecutado)", "tipo": "comando"}, {"name": "source", "emoji": "📥", "cat": "shell", "simple": "Cargar configuración en la sesión actual", "explain": "🔄 Como aplicar los cambios sin cerrar la terminal. Recarga las configuraciones.", "example": "source ~/.bashrc", "output": "(configuración recargada)", "tipo": "comando"}, {"name": "echo $PATH", "emoji": "🗺️", "cat": "shell", "simple": "Ver dónde busca Linux los programas", "explain": "🛤️ Como ver el mapa de caminos donde Linux busca los programas. Si un comando no funciona, revisa esto.", "example": "echo $PATH", "output": "/usr/bin:/bin:/usr/local/bin", "tipo": "comando"}, {"name": "echo $HOME", "emoji": "🏠", "cat": "shell", "simple": "Ver tu carpeta personal", "explain": "🏠 El signo $ antes de HOME significa 'el valor de la variable HOME'. Te dice dónde está tu hogar.", "example": "echo $HOME", "output": "/home/usuario", "tipo": "comando"}, {"name": "echo $USER", "emoji": "👤", "cat": "shell", "simple": "Ver el usuario actual", "explain": "👤 Como preguntarle a la variable: '¿quién soy?' Te dice el nombre de usuario actual.", "example": "echo $USER", "output": "maria", "tipo": "comando"}, {"name": "read", "emoji": "⌨️", "cat": "shell", "simple": "Leer texto que escribe el usuario", "explain": "👂 Como poner un buzón para que el usuario escriba algo. El script espera que escribas.", "example": "read nombre", "output": "(espera que escribas tu nombre)", "tipo": "comando"}, {"name": "if then fi", "emoji": "🤔", "cat": "shell", "simple": "Hacer algo si se cumple una condición", "explain": "🤔 Como decir: 'SI llueve ENTONCES saca el paraguas'. En los scripts se usa mucho esto.", "example": "if [ -f archivo.txt ]; then echo existe; fi", "output": "existe", "tipo": "sintaxis"}, {"name": "for do done", "emoji": "🔄", "cat": "shell", "simple": "Repetir algo varias veces", "explain": "🔁 Como decir: 'para cada alumno, escribe su nombre'. Repite una acción muchas veces.", "example": "for i in 1 2 3; do echo $i; done", "output": "1\n2\n3", "tipo": "sintaxis"}, {"name": "while do done", "emoji": "⏳", "cat": "shell", "simple": "Repetir mientras algo sea verdad", "explain": "🔄 Como decir: 'mientras tengas hambre, sigue comiendo'. Repite hasta que la condición cambie.", "example": "while true; do date; sleep 1; done", "output": "(muestra la fecha cada segundo)", "tipo": "sintaxis"}, {"name": "case esac", "emoji": "📋", "cat": "shell", "simple": "Elegir entre varias opciones", "explain": "📋 Como un menú de restaurante. Dependiendo de lo que elijas, hace una cosa diferente.", "example": "case $opcion in 1) echo uno;; esac", "output": "uno", "tipo": "sintaxis"}, {"name": "exit", "emoji": "🚪", "cat": "shell", "simple": "Salir de la terminal o script", "explain": "🚪 Como salir de una habitación. Cierra la terminal o termina la ejecución de un script.", "example": "exit", "output": "(sesión terminada)", "tipo": "comando"}, {"name": "return", "emoji": "↩️", "cat": "shell", "simple": "Salir de una función", "explain": "↩️ Como terminar de hacer una tarea y volver a donde estabas. Sale de una función.", "example": "return 0", "output": "(sale de la función)", "tipo": "sintaxis"}, {"name": "set", "emoji": "⚙️", "cat": "shell", "simple": "Ver o cambiar opciones del shell", "explain": "🔧 Como el panel de control de bash. Puedes ver todas las variables y cambiar configuraciones.", "example": "set -x", "output": "(activa el modo depuración)", "tipo": "sintaxis"}, {"name": "unset", "emoji": "🗑️", "cat": "shell", "simple": "Eliminar una variable", "explain": "🗑️ Como borrar una nota adhesiva. Elimina una variable y ya no existe más.", "example": "unset MI_VARIABLE", "output": "(variable eliminada)", "tipo": "sintaxis"}, {"name": "declare", "emoji": "📋", "cat": "shell", "simple": "Declarar variables con tipo", "explain": "🏷️ Como etiquetar cajas diciendo qué tipo de cosa guardan: números, texto, etc.", "example": "declare -i numero=5", "output": "(numero es solo entero)", "tipo": "sintaxis"}, {"name": "let", "emoji": "🧮", "cat": "shell", "simple": "Hacer operaciones matemáticas", "explain": "➕ Como una mini calculadora para scripts. Suma, resta, multiplica variables.", "example": "let resultado=5+3", "output": "(resultado=8)", "tipo": "sintaxis"}, {"name": "test", "emoji": "🧪", "cat": "shell", "simple": "Probar condiciones en scripts", "explain": "✅ Como hacer una pregunta de sí/no. Prueba si algo es verdad o mentira en un script.", "example": "test -f archivo.txt && echo existe", "output": "existe", "tipo": "sintaxis"}, {"name": "[ ]", "emoji": "🔲", "cat": "shell", "simple": "Otra forma de hacer pruebas", "explain": "🔲 Como test pero con corchetes. Es la forma más común de hacer condiciones en bash.", "example": "[ -d /home ] && echo es carpeta", "output": "es carpeta", "tipo": "sintaxis"}, {"name": "[[ ]]", "emoji": "🟦", "cat": "shell", "simple": "Pruebas avanzadas en bash", "explain": "🟦 Como [ ] pero más poderoso. Permite usar expresiones más complejas y es más seguro.", "example": "[[ $nombre == 'Ana' ]] && echo hola Ana", "output": "hola Ana", "tipo": "sintaxis"}, {"name": "&&", "emoji": "➕", "cat": "shell", "simple": "Ejecutar si el anterior tuvo éxito", "explain": "✅ Como decir: 'SI lo primero funcionó, haz lo segundo'. Si falla el primero, no hace el segundo.", "example": "mkdir carpeta && echo creada", "output": "creada", "tipo": "sintaxis"}, {"name": "||", "emoji": "↔️", "cat": "shell", "simple": "Ejecutar si el anterior falló", "explain": "❌ Como decir: 'SI lo primero falló, intenta esto'. Es el plan B del scripting.", "example": "ls /no/existe || echo no existe", "output": "no existe", "tipo": "sintaxis"}, {"name": "&", "emoji": "⚡", "cat": "shell", "simple": "Ejecutar en segundo plano", "explain": "👻 El & al final hace que el comando corra en segundo plano. Puedes seguir usando la terminal.", "example": "./proceso_largo.sh &", "output": "[1] 1234", "tipo": "sintaxis"}, {"name": ";;", "emoji": "🔚", "cat": "shell", "simple": "Terminar un caso en switch", "explain": "🔚 En un case/esac, los dos puntos seguidos marcan el final de cada opción.", "example": "case $x in a) echo A;; b) echo B;; esac", "output": "A", "tipo": "sintaxis"}, {"name": "trap", "emoji": "🪤", "cat": "shell", "simple": "Capturar señales del sistema", "explain": "🪤 Como poner una trampa. Cuando el sistema manda una señal (Ctrl+C), ejecutas algo especial.", "example": "trap 'echo ¡Saliendo!' EXIT", "output": "(muestra mensaje al salir)", "tipo": "comando"}, {"name": "getopts", "emoji": "🎛️", "cat": "shell", "simple": "Procesar opciones de un script", "explain": "🎚️ Como leer los parámetros que le das a tu script: -a, -b, -c, etc. Muy útil para scripts.", "example": "getopts 'ab:' opt", "output": "(procesa las opciones del script)", "tipo": "comando"}, {"name": "printf", "emoji": "🖨️", "cat": "shell", "simple": "Mostrar texto con formato", "explain": "🖨️ Como echo pero con más control. Puedes formatear números, alinear texto, etc.", "example": "printf '%-10s %5d\\\\n' Ana 25", "output": "Ana           25", "tipo": "comando"}, {"name": "seq", "emoji": "🔢", "cat": "shell", "simple": "Generar una secuencia de números", "explain": "📊 Como escribir 1, 2, 3, 4... automáticamente. Genera una secuencia de números.", "example": "seq 1 5", "output": "1\n2\n3\n4\n5", "tipo": "comando"}, {"name": "yes", "emoji": "✅", "cat": "shell", "simple": "Repetir 'y' infinitamente", "explain": "🔁 Repite la letra 'y' (yes) sin parar. Útil para responder 'sí' a programas que preguntan.", "example": "yes | apt install programa", "output": "(responde sí a todas las preguntas)", "tipo": "comando"}, {"name": "true", "emoji": "✅", "cat": "shell", "simple": "Comando que siempre tiene éxito", "explain": "✅ Un comando que siempre dice '¡sí, funcionó!' Útil en condiciones y bucles infinitos.", "example": "while true; do echo hola; sleep 1; done", "output": "hola\nhola\nhola...", "tipo": "sintaxis"}, {"name": "false", "emoji": "❌", "cat": "shell", "simple": "Comando que siempre falla", "explain": "❌ Un comando que siempre dice 'fallé'. Útil para probar condiciones de error.", "example": "false || echo el anterior falló", "output": "el anterior falló", "tipo": "sintaxis"}, {"name": "type", "emoji": "🏷️", "cat": "shell", "simple": "Ver el tipo de un comando", "explain": "🔍 Como preguntar: '¿eres un programa real, un alias o una función?' Identifica el tipo.", "example": "type ls", "output": "ls is aliased to 'ls --color=auto'", "tipo": "comando"}, {"name": "hash", "emoji": "#️⃣", "cat": "shell", "simple": "Ver programas recordados por bash", "explain": "💾 Bash recuerda dónde están los programas para no buscarlos cada vez. Esto muestra esa memoria.", "example": "hash", "output": "hits  command\n3  /usr/bin/git", "tipo": "comando"}, {"name": "compgen -c", "emoji": "📋", "cat": "shell", "simple": "Listar todos los comandos disponibles", "explain": "📚 Como ver el diccionario completo de comandos. Lista absolutamente todo lo que puedes ejecutar.", "example": "compgen -c | head", "output": "ls\ncat\ngrep\nawk...", "tipo": "comando"}, {"name": "xdg-open", "emoji": "🖱️", "cat": "shell", "simple": "Abrir archivo con la app correcta", "explain": "🚀 Como hacer doble clic en un archivo. Linux decide qué programa usar y lo abre.", "example": "xdg-open foto.jpg", "output": "(abre foto.jpg con el visor)", "tipo": "comando"}, {"name": "mount", "emoji": "🔌", "cat": "disco", "simple": "Montar un disco o partición", "explain": "🔌 Como enchufar una memoria USB. Le dices a Linux que use ese disco y dónde ponerlo.", "example": "sudo mount /dev/sdb1 /mnt/usb", "output": "(USB disponible en /mnt/usb)", "tipo": "comando"}, {"name": "umount", "emoji": "⏏️", "cat": "disco", "simple": "Desmontar un disco con seguridad", "explain": "⏏️ Como extraer la USB de forma segura. Le dices a Linux que ya no uses ese disco.", "example": "sudo umount /mnt/usb", "output": "(USB desmontada con seguridad)", "tipo": "comando"}, {"name": "mkfs.ext4", "emoji": "🏗️", "cat": "disco", "simple": "Formatear disco con formato ext4", "explain": "🗑️ Como limpiar una memoria y darle formato. Borra TODO y la prepara para Linux.", "example": "sudo mkfs.ext4 /dev/sdb1", "output": "(disco formateado en ext4)", "tipo": "comando"}, {"name": "mkfs.vfat", "emoji": "🗂️", "cat": "disco", "simple": "Formatear disco con formato FAT32", "explain": "💾 Formatea en FAT32, que entienden Windows, Mac y Linux. Bueno para memorias USB.", "example": "sudo mkfs.vfat /dev/sdb1", "output": "(disco formateado en FAT32)", "tipo": "comando"}, {"name": "fsck", "emoji": "🔍", "cat": "disco", "simple": "Revisar y reparar un sistema de archivos", "explain": "🏥 Como llevar el disco al doctor. Busca y repara errores en la estructura del disco.", "example": "sudo fsck /dev/sda1", "output": "fsck: sin errores encontrados", "tipo": "comando"}, {"name": "dd", "emoji": "💽", "cat": "disco", "simple": "Copiar disco byte a byte", "explain": "🖨️ Como fotocopiar exactamente un disco completo. También sirve para crear imágenes de disco.", "example": "sudo dd if=/dev/sda of=backup.img", "output": "(copia exacta del disco)", "tipo": "comando"}, {"name": "dd bs=4M", "emoji": "⚡", "cat": "disco", "simple": "Escribir imagen en USB", "explain": "💿 La forma más común de grabar una ISO en una USB. Útil para instalar sistemas operativos.", "example": "sudo dd bs=4M if=linux.iso of=/dev/sdb", "output": "(grabando ISO en USB)", "tipo": "comando"}, {"name": "sync", "emoji": "💾", "cat": "disco", "simple": "Escribir datos pendientes al disco", "explain": "💾 Como decirle a la computadora: 'guarda todo ahora'. Asegura que nada quede sin guardar.", "example": "sync", "output": "(datos escritos al disco)", "tipo": "comando"}, {"name": "fstab", "emoji": "📋", "cat": "disco", "simple": "Ver discos que se montan al iniciar", "explain": "🗂️ El archivo que le dice a Linux qué discos conectar cuando enciende. Como la lista de tareas del arranque.", "example": "cat /etc/fstab", "output": "/dev/sda1  /  ext4  defaults  0 1", "tipo": "comando"}, {"name": "parted", "emoji": "✂️", "cat": "disco", "simple": "Gestionar particiones del disco", "explain": "🔪 Como el cuchillo para cortar el disco en partes. Crea, borra y modifica particiones.", "example": "sudo parted /dev/sda print", "output": "Número  Inicio  Fin   Tipo\n1      1MB     512MB  primary", "tipo": "instalar"}, {"name": "gparted", "emoji": "🖥️", "cat": "disco", "simple": "Gestionar particiones con interfaz gráfica", "explain": "🖼️ Como parted pero con ventana y botones. Mucho más fácil de usar visualmente.", "example": "sudo gparted", "output": "(abre la interfaz gráfica)", "tipo": "instalar"}, {"name": "swapon", "emoji": "💾", "cat": "disco", "simple": "Activar la memoria swap", "explain": "🔄 La swap es como una extensión de la RAM en el disco. swapon la activa cuando se necesita.", "example": "sudo swapon -a", "output": "(swap activada)", "tipo": "comando"}, {"name": "swapoff", "emoji": "⏹️", "cat": "disco", "simple": "Desactivar la memoria swap", "explain": "🔄 Desactiva la swap. Útil antes de cambiar su tamaño o eliminarla.", "example": "sudo swapoff -a", "output": "(swap desactivada)", "tipo": "comando"}, {"name": "mkswap", "emoji": "🔄", "cat": "disco", "simple": "Crear una partición swap", "explain": "🏗️ Como preparar el espacio de emergencia para la RAM. Formatea una partición como swap.", "example": "sudo mkswap /dev/sda3", "output": "(partición swap creada)", "tipo": "comando"}, {"name": "iostat", "emoji": "📊", "cat": "disco", "simple": "Ver estadísticas de uso del disco", "explain": "📈 Como el velocímetro del disco. Muestra qué tan rápido está leyendo y escribiendo.", "example": "iostat", "output": "Device  Read/s  Write/s\nsda     1.2MB   0.5MB", "tipo": "instalar"}, {"name": "iotop", "emoji": "🔝", "cat": "disco", "simple": "Ver qué proceso usa más el disco", "explain": "📊 Como top pero para el disco. Muestra qué programa está leyendo o escribiendo más.", "example": "sudo iotop", "output": "PID  R/s    W/s   COMANDO\n123  2.5M   0.1M  firefox", "tipo": "instalar"}, {"name": "lsof -u", "emoji": "🔍", "cat": "disco", "simple": "Ver archivos abiertos por un usuario", "explain": "🗂️ Como saber qué libros tiene prestados una persona específica. Lista archivos de un usuario.", "example": "lsof -u maria", "output": "bash   123  maria  /home/maria/.bashrc", "tipo": "comando"}, {"name": "tune2fs", "emoji": "⚙️", "cat": "disco", "simple": "Ajustar parámetros de ext2/3/4", "explain": "🔧 Como el panel de ajustes del sistema de archivos. Puedes cambiar la frecuencia de revisiones, etc.", "example": "sudo tune2fs -l /dev/sda1", "output": "Filesystem state: clean\nBlock count: 1048576", "tipo": "instalar"}, {"name": "e2fsck", "emoji": "🔍", "cat": "disco", "simple": "Revisar sistema de archivos ext", "explain": "🏥 El doctor especializado en sistemas de archivos ext. Más detallado que fsck.", "example": "sudo e2fsck -f /dev/sda1", "output": "Pass 1: sin errores\nPass 2: sin errores", "tipo": "instalar"}, {"name": "cryptsetup", "emoji": "🔐", "cat": "disco", "simple": "Cifrar un disco o partición", "explain": "🔒 Como ponerle cerradura al disco. Nadie puede leer los datos sin la contraseña correcta.", "example": "sudo cryptsetup luksFormat /dev/sdb", "output": "(partición cifrada con LUKS)", "tipo": "instalar"}, {"name": "ls -a", "emoji": "👁️", "cat": "archivos", "simple": "Ver archivos ocultos también", "explain": "🕵️ Los archivos que empiezan con punto están ocultos. Con -a los ves todos, hasta los secretos.", "example": "ls -a", "output": ".bashrc  .ssh  fotos  musica", "tipo": "comando"}, {"name": "ls -S", "emoji": "📊", "cat": "archivos", "simple": "Listar archivos por tamaño", "explain": "⚖️ Muestra primero los archivos más grandes, como ordenar juguetes de grande a pequeño.", "example": "ls -S", "output": "video.mp4  foto.jpg  nota.txt", "tipo": "comando"}, {"name": "readlink", "emoji": "🔗", "cat": "archivos", "simple": "Ver a dónde apunta un enlace simbólico", "explain": "🏹 Como preguntar: '¿adónde lleva este atajo?' Te muestra la ruta real del acceso directo.", "example": "readlink atajo.txt", "output": "/home/usuario/original.txt", "tipo": "comando"}, {"name": "install", "emoji": "📥", "cat": "archivos", "simple": "Copiar archivo con permisos específicos", "explain": "🏗️ Como cp pero también ajusta los permisos al mismo tiempo. Muy útil para instalar programas.", "example": "install -m 755 programa /usr/local/bin/", "output": "(programa instalado con permisos)", "tipo": "comando"}, {"name": "rename", "emoji": "✏️", "cat": "archivos", "simple": "Renombrar múltiples archivos", "explain": "✏️ Como cambiarle el nombre a muchos archivos a la vez con un patrón. Muy poderoso.", "example": "rename 's/.txt/.md/' *.txt", "output": "(todos los .txt ahora son .md)", "tipo": "instalar"}, {"name": "cmp", "emoji": "🔍", "cat": "archivos", "simple": "Comparar dos archivos byte a byte", "explain": "🔬 Como comparar dos copias de un libro letra por letra. Te dice exactamente dónde son diferentes.", "example": "cmp archivo1.bin archivo2.bin", "output": "archivo1.bin archivo2.bin difieren en el byte 100", "tipo": "comando"}, {"name": "od", "emoji": "🔢", "cat": "archivos", "simple": "Ver un archivo en formato octal/hexadecimal", "explain": "🔢 Como leer el código secreto binario de un archivo. Muestra los bytes en diferentes formatos.", "example": "od -c foto.jpg | head", "output": "0000000  \\\\377 \\\\330 \\\\377 ...", "tipo": "instalar"}, {"name": "xxd", "emoji": "🔐", "cat": "archivos", "simple": "Ver archivo en hexadecimal", "explain": "💻 Como od pero más bonito. Muestra el archivo en hexadecimal y también su versión texto.", "example": "xxd nota.txt | head", "output": "00000000: 486f 6c61  Hola", "tipo": "instalar"}, {"name": "lz4", "emoji": "💨", "cat": "archivos", "simple": "Comprimir muy rápido con lz4", "explain": "⚡ El velocista de la compresión. No comprime tanto como xz pero es muchísimo más rápido.", "example": "lz4 archivo.txt", "output": "(crea archivo.txt.lz4 rápidamente)", "tipo": "instalar"}, {"name": "zcat", "emoji": "👁️", "cat": "archivos", "simple": "Leer archivo .gz sin descomprimirlo", "explain": "🔍 Como leer el contenido de un archivo comprimido sin tener que abrirlo. ¡Ahorra tiempo!", "example": "zcat archivo.txt.gz", "output": "Hola, soy el contenido comprimido", "tipo": "instalar"}, {"name": "zgrep", "emoji": "🔍", "cat": "archivos", "simple": "Buscar dentro de archivos .gz", "explain": "🧲 Como grep pero para archivos comprimidos. Busca sin tener que descomprimir primero.", "example": "zgrep 'error' log.gz", "output": "línea con error dentro del .gz", "tipo": "instalar"}, {"name": "systemctl start", "emoji": "▶️", "cat": "sistema", "simple": "Iniciar un servicio del sistema", "explain": "▶️ Como darle play a un servicio. Inicia un programa que corre en segundo plano.", "example": "sudo systemctl start nginx", "output": "(nginx iniciado)", "tipo": "comando"}, {"name": "systemctl stop", "emoji": "⏹️", "cat": "sistema", "simple": "Detener un servicio del sistema", "explain": "⏹️ Como darle stop a un servicio. Para un programa que corre en segundo plano.", "example": "sudo systemctl stop nginx", "output": "(nginx detenido)", "tipo": "comando"}, {"name": "systemctl restart", "emoji": "🔄", "cat": "sistema", "simple": "Reiniciar un servicio", "explain": "🔁 Como apagar y encender un servicio. Útil cuando cambiaste su configuración.", "example": "sudo systemctl restart nginx", "output": "(nginx reiniciado)", "tipo": "comando"}, {"name": "systemctl enable", "emoji": "⚡", "cat": "sistema", "simple": "Activar servicio al arrancar", "explain": "🔌 Como decir: 'cuando encienda la compu, que este servicio empiece solo'.", "example": "sudo systemctl enable nginx", "output": "(nginx arrancará al inicio)", "tipo": "comando"}, {"name": "systemctl disable", "emoji": "🔌", "cat": "sistema", "simple": "Desactivar servicio al arrancar", "explain": "🔌 Lo opuesto al enable. El servicio ya no arrancará automáticamente.", "example": "sudo systemctl disable nginx", "output": "(nginx ya no arrancará solo)", "tipo": "comando"}, {"name": "systemctl status", "emoji": "📊", "cat": "sistema", "simple": "Ver estado de un servicio", "explain": "🩺 Como revisar si un servicio está sano. Te dice si está corriendo, parado, o con errores.", "example": "systemctl status nginx", "output": "● nginx.service - nginx\n   Active: active (running)", "tipo": "comando"}, {"name": "systemctl list-units", "emoji": "📋", "cat": "sistema", "simple": "Listar todos los servicios", "explain": "📋 Como el inventario de todos los servicios del sistema. Los activos, parados y fallidos.", "example": "systemctl list-units --type=service", "output": "nginx.service  active\nssh.service   active", "tipo": "comando"}, {"name": "service", "emoji": "⚙️", "cat": "sistema", "simple": "Gestionar servicios (forma clásica)", "explain": "⚙️ El abuelo de systemctl. En sistemas más antiguos se usa para arrancar y parar servicios.", "example": "sudo service apache2 start", "output": "(apache2 iniciado)", "tipo": "comando"}, {"name": "init", "emoji": "🚀", "cat": "sistema", "simple": "Ver o cambiar nivel de ejecución", "explain": "🎚️ Como el nivel de funcionamiento del sistema. 0 es apagado, 6 es reiniciar, 3 es normal.", "example": "sudo init 6", "output": "(reiniciando el sistema)", "tipo": "comando"}, {"name": "runlevel", "emoji": "🔢", "cat": "sistema", "simple": "Ver el nivel de ejecución actual", "explain": "🔢 Muestra en qué 'modo' está corriendo el sistema en este momento.", "example": "runlevel", "output": "N 5", "tipo": "comando"}, {"name": "last reboot", "emoji": "🔄", "cat": "sistema", "simple": "Ver cuándo se reinició la compu", "explain": "📅 Como ver el historial de reinicios. Te dice cuándo y cuántas veces se ha reiniciado.", "example": "last reboot", "output": "reboot  system boot  dom mar 8 09:00", "tipo": "comando"}, {"name": "logrotate", "emoji": "🔄", "cat": "sistema", "simple": "Rotar archivos de registro", "explain": "📰 Como renovar periódicos viejos. Mueve, comprime y borra logs viejos automáticamente.", "example": "sudo logrotate /etc/logrotate.conf", "output": "(logs rotados y comprimidos)", "tipo": "comando"}, {"name": "sysctl", "emoji": "⚙️", "cat": "sistema", "simple": "Ver y cambiar parámetros del kernel", "explain": "🔧 Como el panel de control del núcleo de Linux. Puedes ajustar comportamientos muy específicos.", "example": "sysctl kernel.hostname", "output": "kernel.hostname = mi-laptop", "tipo": "comando"}, {"name": "ulimit", "emoji": "🔒", "cat": "sistema", "simple": "Ver límites de recursos del sistema", "explain": "📏 Como las reglas que dicen cuántos archivos puede abrir cada proceso. Límites de seguridad.", "example": "ulimit -a", "output": "open files: 1024\nmax processes: 31627", "tipo": "comando"}, {"name": "vmstat", "emoji": "📊", "cat": "sistema", "simple": "Ver estadísticas de memoria y CPU", "explain": "📈 Como el tablero de instrumentos de la compu. Memoria, CPU, disco, todo en un vistazo.", "example": "vmstat 1 5", "output": "r  b   swpd   free  buff\n1  0      0  4096  1024", "tipo": "instalar"}, {"name": "sar", "emoji": "📊", "cat": "sistema", "simple": "Ver estadísticas históricas del sistema", "explain": "📚 Como un cuaderno de registros del rendimiento. Guarda cómo se comportó el sistema en el tiempo.", "example": "sar -u 1 3", "output": "10:00:01  %user  %system  %idle\n10:00:02   5.00   1.00   94.00", "tipo": "instalar"}, {"name": "ip link", "emoji": "🔌", "cat": "red", "simple": "Ver interfaces de red", "explain": "🔌 Muestra todas las interfaces de red: Ethernet, WiFi, loopback. Como ver todos los enchufes.", "example": "ip link", "output": "1: lo: &lt;LOOPBACK&gt;\n2: eth0: &lt;BROADCAST&gt;", "tipo": "comando"}, {"name": "ip link set", "emoji": "🔌", "cat": "red", "simple": "Activar/desactivar una interfaz", "explain": "💡 Como el interruptor de la red. Puedes encender o apagar una tarjeta de red específica.", "example": "sudo ip link set eth0 up", "output": "(eth0 activada)", "tipo": "comando"}, {"name": "tcpdump", "emoji": "🔭", "cat": "red", "simple": "Capturar tráfico de red", "explain": "🕵️ Como poner un micrófono en la red. Captura y muestra todos los datos que pasan.", "example": "sudo tcpdump -i eth0", "output": "IP 192.168.1.5 &gt; google.com: ...", "tipo": "instalar"}, {"name": "iperf", "emoji": "⚡", "cat": "red", "simple": "Medir velocidad de la red", "explain": "🏎️ Como hacer una carrera de velocidad con la red. Mide qué tan rápido van los datos.", "example": "iperf -c 192.168.1.1", "output": "Bandwidth: 94.5 Mbits/sec", "tipo": "instalar"}, {"name": "netcat", "emoji": "📞", "cat": "red", "simple": "Conectar y transferir datos por red", "explain": "☎️ Como nc, otra forma de llamarlo. Crea conexiones de red simples para enviar datos.", "example": "netcat -l 9000", "output": "(escuchando en puerto 9000)", "tipo": "instalar"}, {"name": "socat", "emoji": "🔄", "cat": "red", "simple": "Conectar dos flujos de datos", "explain": "🔀 Como un enchufe múltiple para datos. Conecta cualquier cosa con cualquier cosa: red, archivos, etc.", "example": "socat TCP-LISTEN:1234 STDOUT", "output": "(retransmite todo lo que llega)", "tipo": "instalar"}, {"name": "proxychains", "emoji": "🔗", "cat": "red", "simple": "Redirigir tráfico por proxy", "explain": "🔗 Como hacer que el tráfico pase por intermediarios antes de llegar a su destino.", "example": "proxychains firefox", "output": "(firefox usa el proxy configurado)", "tipo": "instalar"}, {"name": "host -t MX", "emoji": "📧", "cat": "red", "simple": "Ver servidores de correo de un dominio", "explain": "📮 Como ver a qué oficina de correos va el mail de una empresa. Muestra los servidores MX.", "example": "host -t MX gmail.com", "output": "gmail.com mail is handled by google.com", "tipo": "comando"}, {"name": "curl -I", "emoji": "🔍", "cat": "red", "simple": "Ver cabeceras HTTP de una página", "explain": "📋 Como pedir solo la etiqueta de un paquete sin abrir el paquete. Solo las cabeceras HTTP.", "example": "curl -I https://google.com", "output": "HTTP/2 200\ncontent-type: text/html", "tipo": "comando"}, {"name": "wget --spider", "emoji": "🕷️", "cat": "red", "simple": "Verificar si una URL existe", "explain": "🔍 Como tocar el timbre para saber si hay alguien. Comprueba si la página existe sin descargarla.", "example": "wget --spider https://ejemplo.com", "output": "URL existe y es accesible", "tipo": "comando"}, {"name": "uptime -p", "emoji": "⏰", "cat": "procesos", "simple": "Ver tiempo activo en formato bonito", "explain": "⏱️ Muestra cuánto lleva encendida la compu en un formato fácil de leer: '3 días, 2 horas'.", "example": "uptime -p", "output": "up 3 days, 2 hours, 15 minutes", "tipo": "comando"}, {"name": "taskset", "emoji": "🎯", "cat": "procesos", "simple": "Asignar proceso a un núcleo de CPU", "explain": "🎯 Como decirle a un trabajador que solo use un escritorio específico. Fija un proceso a una CPU.", "example": "taskset -c 0 programa", "output": "(programa usa solo el núcleo 0)", "tipo": "instalar"}, {"name": "ionice", "emoji": "📊", "cat": "procesos", "simple": "Ajustar prioridad de acceso al disco", "explain": "📊 Como nice pero para el disco. Decide qué proceso tiene prioridad para leer/escribir.", "example": "ionice -c 3 programa", "output": "(programa tiene prioridad baja de disco)", "tipo": "instalar"}, {"name": "chrt", "emoji": "⚡", "cat": "procesos", "simple": "Cambiar política de planificación", "explain": "⚡ Para procesos que necesitan respuesta en tiempo real. Muy técnico pero muy poderoso.", "example": "chrt -r 99 programa", "output": "(proceso con prioridad máxima en tiempo real)", "tipo": "instalar"}, {"name": "nsenter", "emoji": "🚪", "cat": "procesos", "simple": "Entrar al espacio de nombres de un proceso", "explain": "🎭 Como entrar al mundo de un proceso específico. Útil para trabajar con contenedores Docker.", "example": "sudo nsenter -t 1234 --net", "output": "(en el namespace de red del proceso 1234)", "tipo": "instalar"}, {"name": "pstree", "emoji": "🌳", "cat": "procesos", "simple": "Ver procesos en forma de árbol", "explain": "🌲 Como el árbol familiar de los procesos. Muestra quién creó a quién, de padre a hijo.", "example": "pstree", "output": "systemd─┬─bash─└─sleep\n        └─sshd", "tipo": "instalar"}, {"name": "mpstat", "emoji": "📊", "cat": "procesos", "simple": "Ver uso de cada núcleo de CPU", "explain": "📊 Como ver el consumo de energía de cada cerebrito del procesador por separado.", "example": "mpstat -P ALL", "output": "CPU  %usr  %sys  %idle\n0    5.0   1.0   94.0\n1    3.0   0.5   96.5", "tipo": "instalar"}, {"name": "pidstat", "emoji": "📊", "cat": "procesos", "simple": "Ver estadísticas de procesos", "explain": "📈 Como un monitor deportivo para los procesos. Muestra CPU, memoria y disco por proceso.", "example": "pidstat 1", "output": "PID   %CPU  %MEM  Comando\n1234  5.0   1.2   firefox", "tipo": "instalar"}, {"name": "sed -n", "emoji": "📄", "cat": "texto", "simple": "Mostrar solo ciertas líneas", "explain": "🎯 Sed en modo silencioso. Solo muestra las líneas que le dices, como abrir un libro en cierta página.", "example": "sed -n '5,10p' archivo.txt", "output": "(muestra solo líneas 5 a 10)", "tipo": "comando"}, {"name": "sed -i", "emoji": "✏️", "cat": "texto", "simple": "Editar archivo directamente", "explain": "✏️ Sed que modifica el archivo en su lugar. No necesitas guardar en otro archivo.", "example": "sed -i 's/error/éxito/g' log.txt", "output": "(log.txt modificado directamente)", "tipo": "comando"}, {"name": "perl -pe", "emoji": "🐪", "cat": "texto", "simple": "Editar texto con Perl", "explain": "🐪 Perl es un lenguaje muy potente para texto. -pe significa: aplica esto a cada línea.", "example": "perl -pe 's/gato/perro/g' archivo.txt", "output": "(reemplaza en todas las líneas)", "tipo": "instalar"}, {"name": "python3 -c", "emoji": "🐍", "cat": "texto", "simple": "Ejecutar Python en una línea", "explain": "🐍 Como abrir Python y escribir una línea. Muy útil para cálculos o transformaciones rápidas.", "example": "python3 -c 'print(2**10)'", "output": "1024", "tipo": "instalar"}, {"name": "xmllint", "emoji": "📄", "cat": "texto", "simple": "Procesar y validar XML", "explain": "🔍 Como jq pero para XML. Valida y formatea archivos XML.", "example": "xmllint --format datos.xml", "output": "(XML formateado y bonito)", "tipo": "instalar"}, {"name": "csvtool", "emoji": "📊", "cat": "texto", "simple": "Procesar archivos CSV", "explain": "📊 Una herramienta específica para CSV. Corta columnas, filtra filas, etc.", "example": "csvtool col 1,3 datos.csv", "output": "(columnas 1 y 3 del CSV)", "tipo": "instalar"}, {"name": "!!", "emoji": "⏫", "cat": "shell", "simple": "Repetir el último comando", "explain": "🔁 Como presionar la flecha arriba y Enter. Ejecuta exactamente el mismo comando de antes.", "example": "!!", "output": "(repite el último comando)", "tipo": "sintaxis"}, {"name": "!$", "emoji": "🔚", "cat": "shell", "simple": "Usar el último argumento del comando anterior", "explain": "🏁 Como copiar el último argumento. Si antes escribiste 'cat nota.txt', !$ es 'nota.txt'.", "example": "cat archivo.txt\\nls -l !$", "output": "(usa archivo.txt como argumento)", "tipo": "sintaxis"}, {"name": "ctrl+r", "emoji": "🔍", "cat": "shell", "simple": "Buscar en el historial", "explain": "🔍 Como Ctrl+F pero para el historial. Escribe algo y busca el último comando que lo usó.", "example": "(presiona Ctrl+R y escribe)", "output": "(muestra comandos del historial)", "tipo": "atajo"}, {"name": "ctrl+c", "emoji": "🛑", "cat": "shell", "simple": "Cancelar el comando actual", "explain": "🛑 El botón de emergencia. Cancela lo que se está ejecutando ahora mismo.", "example": "(presiona Ctrl+C durante un comando)", "output": "(comando cancelado)", "tipo": "atajo"}, {"name": "ctrl+z", "emoji": "⏸️", "cat": "shell", "simple": "Pausar el comando actual", "explain": "⏸️ Como pausar un video. Pausa el programa que está corriendo y lo manda al fondo.", "example": "(presiona Ctrl+Z durante un comando)", "output": "[1]+  Stopped  programa", "tipo": "atajo"}, {"name": "ctrl+d", "emoji": "🚪", "cat": "shell", "simple": "Cerrar la terminal o enviar EOF", "explain": "🚪 Como escribir 'exit' pero más rápido. Cierra la terminal o termina la entrada de datos.", "example": "(presiona Ctrl+D al final)", "output": "(terminal cerrada)", "tipo": "atajo"}, {"name": "ctrl+l", "emoji": "🧹", "cat": "shell", "simple": "Limpiar pantalla con atajo", "explain": "🧽 Como escribir 'clear' pero más rápido. Limpia la pantalla instantáneamente.", "example": "(presiona Ctrl+L)", "output": "(pantalla limpia)", "tipo": "atajo"}, {"name": "ctrl+a", "emoji": "⬅️", "cat": "shell", "simple": "Ir al inicio de la línea", "explain": "⏮️ Como Home en el teclado. Te lleva al principio de la línea que estás escribiendo.", "example": "(presiona Ctrl+A)", "output": "(cursor al inicio de la línea)", "tipo": "atajo"}, {"name": "ctrl+e", "emoji": "➡️", "cat": "shell", "simple": "Ir al final de la línea", "explain": "⏭️ Como End en el teclado. Te lleva al final de la línea que estás escribiendo.", "example": "(presiona Ctrl+E)", "output": "(cursor al final de la línea)", "tipo": "atajo"}, {"name": "tab", "emoji": "⭐", "cat": "shell", "simple": "Autocompletar comandos", "explain": "🪄 La tecla mágica de Linux. Empieza a escribir algo y presiona Tab para que lo complete solo.", "example": "ls Do[TAB]", "output": "ls Documentos/", "tipo": "atajo"}, {"name": "heredoc <<", "emoji": "📄", "cat": "shell", "simple": "Escribir texto multilínea en scripts", "explain": "📝 Como escribir varias líneas de texto dentro de un script. Muy útil para crear archivos.", "example": "cat << EOF\\nHola\\nMundo\\nEOF", "output": "Hola\nMundo", "tipo": "sintaxis"}, {"name": "process substitution <()", "emoji": "🔄", "cat": "shell", "simple": "Usar salida de comando como archivo", "explain": "🔀 Como darle a un comando la salida de otro como si fuera un archivo.", "example": "diff <(ls dir1) <(ls dir2)", "output": "(compara contenido de dos carpetas)", "tipo": "sintaxis"}, {"name": "bash -x", "emoji": "🔬", "cat": "shell", "simple": "Ejecutar script en modo debug", "explain": "🔍 Como poner lupa al script. Muestra cada comando antes de ejecutarlo para ver qué pasa.", "example": "bash -x mi_script.sh", "output": "+ echo hola\nhola\n+ ls", "tipo": "sintaxis"}, {"name": "set -e", "emoji": "🛑", "cat": "shell", "simple": "Detener script si hay un error", "explain": "🚨 Como un interruptor de seguridad. Si algo falla, el script para en vez de continuar con errores.", "example": "set -e", "output": "(script para si hay error)", "tipo": "sintaxis"}, {"name": "set -u", "emoji": "⚠️", "cat": "shell", "simple": "Error si se usa variable no definida", "explain": "⚠️ Protección extra. Si usas una variable que no existe, da error en vez de continuar silencioso.", "example": "set -u", "output": "(error si usas variable vacía)", "tipo": "sintaxis"}, {"name": "$(comando)", "emoji": "🔄", "cat": "shell", "simple": "Usar resultado de un comando", "explain": "🎁 Como guardar el resultado de un comando para usarlo. $() ejecuta y usa su salida.", "example": "echo Hoy es $(date)", "output": "Hoy es dom mar  8 10:30 2026", "tipo": "sintaxis"}, {"name": "cpupower", "emoji": "⚡", "cat": "hardware", "simple": "Gestionar la frecuencia del CPU", "explain": "🎚️ Como el acelerador del procesador. Puedes hacerlo más rápido o más lento para ahorrar energía.", "example": "cpupower frequency-info", "output": "current policy: 2.4 GHz", "tipo": "instalar"}, {"name": "powertop", "emoji": "🔋", "cat": "hardware", "simple": "Ver qué consume más batería", "explain": "🔋 Como el monitor de batería. Muestra qué programas gastan más energía.", "example": "sudo powertop", "output": "Power: 8.5 W\nfirefox: 2.1 W", "tipo": "instalar"}, {"name": "acpi", "emoji": "🔋", "cat": "hardware", "simple": "Ver estado de la batería", "explain": "🔋 Como ver el indicador de batería pero en texto. Muestra porcentaje y si está cargando.", "example": "acpi", "output": "Battery 0: Discharging, 85%, 02:30:00", "tipo": "instalar"}, {"name": "lshw", "emoji": "📋", "cat": "hardware", "simple": "Ver todo el hardware del sistema", "explain": "🔬 El informe médico completo de tu computadora. Lista absolutamente todo el hardware.", "example": "sudo lshw -short", "output": "bus  Motherboard: ...\ndisk: Samsung 500GB", "tipo": "instalar"}, {"name": "biosdecode", "emoji": "🔍", "cat": "hardware", "simple": "Ver información de la BIOS", "explain": "🧬 Como leer el ADN de la BIOS. Muestra información del firmware de la placa madre.", "example": "sudo biosdecode", "output": "SMBIOS: version 3.0\nBIOS: AMI 2024", "tipo": "instalar"}, {"name": "turbostat", "emoji": "📊", "cat": "hardware", "simple": "Ver estadísticas de la CPU en detalle", "explain": "📈 El monitor super detallado del procesador. Muestra frecuencia, temperatura, y consumo.", "example": "sudo turbostat", "output": "CPU  Avg_MHz  Bzy_MHz  TSC_MHz  Tmp\n0    800      2400     2401     45", "tipo": "instalar"}, {"name": "numactl", "emoji": "🗺️", "cat": "hardware", "simple": "Controlar la política de memoria NUMA", "explain": "🧠 Para computadoras con múltiples procesadores. Controla qué memoria usa cada proceso.", "example": "numactl --hardware", "output": "available: 2 nodes (0-1)", "tipo": "instalar"}, {"name": "ethtool", "emoji": "🔌", "cat": "hardware", "simple": "Ver y configurar tarjeta de red", "explain": "⚙️ El panel de control de tu tarjeta Ethernet. Velocidad, duplex, estado del cable.", "example": "ethtool eth0", "output": "Speed: 1000Mb/s\nDuplex: Full\nLink detected: yes", "tipo": "instalar"}, {"name": "snap refresh", "emoji": "🔄", "cat": "paquetes", "simple": "Actualizar paquetes snap", "explain": "⬆️ Como actualizar apps de la tienda Snap. Descarga las versiones más nuevas.", "example": "sudo snap refresh", "output": "(todos los snaps actualizados)", "tipo": "instalar"}, {"name": "flatpak update", "emoji": "⬆️", "cat": "paquetes", "simple": "Actualizar paquetes flatpak", "explain": "⬆️ Actualiza todas las aplicaciones instaladas con Flatpak.", "example": "flatpak update", "output": "(flatpaks actualizados)", "tipo": "instalar"}, {"name": "apt-cache", "emoji": "🗃️", "cat": "paquetes", "simple": "Consultar la caché de paquetes", "explain": "🗂️ Como ver el catálogo local de la tienda. Busca información de paquetes sin internet.", "example": "apt-cache search editor", "output": "nano - editor de texto simple\nvim - editor avanzado", "tipo": "comando"}, {"name": "dpkg --get-selections", "emoji": "📋", "cat": "paquetes", "simple": "Listar todos los paquetes instalados", "explain": "📋 Una lista completa de todo lo que tienes instalado. Muy útil para hacer respaldos.", "example": "dpkg --get-selections", "output": "firefox  install\nnano  install", "tipo": "comando"}, {"name": "add-apt-repository", "emoji": "➕", "cat": "paquetes", "simple": "Añadir repositorio de software", "explain": "🏪 Como añadir una tienda extra a tu lista de tiendas. Da acceso a más programas.", "example": "sudo add-apt-repository ppa:usuario/ppa", "output": "(repositorio añadido)", "tipo": "comando"}, {"name": "apt-key", "emoji": "🔑", "cat": "paquetes", "simple": "Gestionar llaves de repositorios", "explain": "🔑 Las llaves que verifican que los paquetes son seguros y auténticos.", "example": "sudo apt-key list", "output": "(muestra las llaves de confianza)", "tipo": "comando"}, {"name": "pip freeze", "emoji": "🧊", "cat": "paquetes", "simple": "Listar paquetes Python con versiones", "explain": "🧊 Como hacer una foto de todos tus módulos Python con sus versiones exactas.", "example": "pip freeze", "output": "requests==2.31.0\nnumpy==1.26.0", "tipo": "instalar"}, {"name": "pip uninstall", "emoji": "🗑️", "cat": "paquetes", "simple": "Desinstalar módulo Python", "explain": "🗑️ Como quitar una herramienta de Python. La desinstala del sistema.", "example": "pip uninstall requests", "output": "(requests desinstalado)", "tipo": "instalar"}, {"name": "npm update", "emoji": "🔄", "cat": "paquetes", "simple": "Actualizar paquetes Node.js", "explain": "⬆️ Como actualizar las herramientas de JavaScript. Busca versiones más nuevas.", "example": "npm update", "output": "(paquetes actualizados)", "tipo": "instalar"}, {"name": "npm list", "emoji": "📋", "cat": "paquetes", "simple": "Listar paquetes Node instalados", "explain": "📋 Como ver tu caja de herramientas de JavaScript. Lista todos los paquetes npm.", "example": "npm list", "output": "mi-proyecto\n├── express@4.18.2\n└── lodash@4.17.21", "tipo": "instalar"}, {"name": "tput", "emoji": "🎨", "cat": "sistema", "simple": "Controlar la terminal", "explain": "🎨 Como el control remoto de la terminal. Puedes cambiar colores, mover el cursor, limpiar, etc.", "example": "tput setaf 2; echo Hola verde", "output": "Hola verde (en color verde)", "tipo": "comando"}, {"name": "stty", "emoji": "⌨️", "cat": "sistema", "simple": "Configurar terminal y teclado", "explain": "🎛️ Como ajustar el teclado de la terminal. Puedes cambiar velocidad, teclas especiales, etc.", "example": "stty -a", "output": "speed 38400 baud; rows 24; columns 80", "tipo": "comando"}, {"name": "script", "emoji": "📹", "cat": "sistema", "simple": "Grabar todo lo que pasa en la terminal", "explain": "📹 Como grabar un video de tu terminal. Guarda todo lo que escribes y ves.", "example": "script mi_sesion.txt", "output": "(grabando sesión en mi_sesion.txt)", "tipo": "instalar"}, {"name": "scriptreplay", "emoji": "▶️", "cat": "sistema", "simple": "Reproducir una sesión grabada", "explain": "▶️ Como ver la repetición de un partido. Reproduce exactamente lo que pasó en la terminal.", "example": "scriptreplay tiempos.txt mi_sesion.txt", "output": "(reproduciendo sesión grabada)", "tipo": "instalar"}, {"name": "wall", "emoji": "📢", "cat": "sistema", "simple": "Enviar mensaje a todos los usuarios", "explain": "📣 Como hacer un anuncio por el altavoz del colegio. El mensaje llega a todos los usuarios.", "example": "echo 'Reiniciando en 5 min' | wall", "output": "Broadcast de maria: Reiniciando en 5 min", "tipo": "instalar"}, {"name": "write", "emoji": "💬", "cat": "sistema", "simple": "Enviar mensaje a un usuario específico", "explain": "💌 Como mandarle una nota a alguien. Le envías un mensaje directo a un usuario conectado.", "example": "write pedro", "output": "(escribe y Enter para enviar)", "tipo": "instalar"}, {"name": "mesg", "emoji": "🔕", "cat": "sistema", "simple": "Activar/desactivar mensajes entrantes", "explain": "📵 Como silenciar las notificaciones. Decides si recibes o no mensajes de otros usuarios.", "example": "mesg n", "output": "(mensajes desactivados)", "tipo": "instalar"}, {"name": "notify-send", "emoji": "🔔", "cat": "sistema", "simple": "Enviar notificación de escritorio", "explain": "🔔 Como mandar una notificación emergente al escritorio. ¡Aparece un globito en la pantalla!", "example": "notify-send 'Hola' 'Esta es una notificación'", "output": "(notificación aparece en el escritorio)", "tipo": "instalar"}, {"name": "xclip", "emoji": "📋", "cat": "sistema", "simple": "Copiar y pegar desde terminal", "explain": "📋 Como Ctrl+C y Ctrl+V pero desde la terminal. Copia texto al portapapeles.", "example": "echo 'Hola' | xclip -selection clipboard", "output": "(texto copiado al portapapeles)", "tipo": "instalar"}, {"name": "xdotool", "emoji": "🖱️", "cat": "sistema", "simple": "Simular clics y teclas del teclado", "explain": "🤖 Como un robot que controla el ratón y teclado. Puede hacer clic y escribir automáticamente.", "example": "xdotool type 'Hola Mundo'", "output": "(escribe 'Hola Mundo' automáticamente)", "tipo": "instalar"}, {"name": "convert", "emoji": "🔄", "cat": "archivos", "simple": "Convertir imágenes de formato", "explain": "🖼️ De ImageMagick. Convierte fotos entre formatos: JPG, PNG, GIF, etc.", "example": "convert foto.png foto.jpg", "output": "(foto.png convertida a foto.jpg)", "tipo": "instalar"}, {"name": "ffmpeg", "emoji": "🎬", "cat": "archivos", "simple": "Convertir videos y audio", "explain": "🎬 El cuchillo suizo del multimedia. Convierte, corta y transforma videos y audios.", "example": "ffmpeg -i video.mp4 audio.mp3", "output": "(extrae audio del video)", "tipo": "instalar"}, {"name": "exiftool", "emoji": "📸", "cat": "archivos", "simple": "Ver metadatos de fotos", "explain": "📸 Como leer los datos secretos de una foto: cámara usada, fecha, ubicación GPS, etc.", "example": "exiftool foto.jpg", "output": "Camera Model: iPhone 15\nGPS: 19.432, -99.133", "tipo": "instalar"}, {"name": "gpg", "emoji": "🔏", "cat": "permisos", "simple": "Cifrar y firmar archivos", "explain": "🔏 Como un sobre sellado con tu firma. Cifra archivos para que solo tú o quien quieras los abra.", "example": "gpg -c secreto.txt", "output": "(crea secreto.txt.gpg cifrado)", "tipo": "instalar"}, {"name": "gpg -d", "emoji": "🔓", "cat": "permisos", "simple": "Descifrar un archivo GPG", "explain": "🔓 Como abrir el sobre sellado. Descifra el archivo si tienes la contraseña correcta.", "example": "gpg -d secreto.txt.gpg", "output": "(muestra el contenido descifrado)", "tipo": "comando"}, {"name": "openssl", "emoji": "🔒", "cat": "red", "simple": "Herramienta de cifrado y certificados", "explain": "🔐 Como la caja fuerte de internet. Crea certificados, cifra datos y verifica conexiones seguras.", "example": "openssl rand -hex 32", "output": "a1b2c3d4e5f6... (clave aleatoria)", "tipo": "instalar"}, {"name": "ssh-agent", "emoji": "🔑", "cat": "red", "simple": "Agente para gestionar llaves SSH", "explain": "🤝 Como un llavero inteligente. Recuerda tus llaves SSH para que no tengas que escribir contraseña cada vez.", "example": "eval $(ssh-agent)", "output": "Agent pid 1234", "tipo": "comando"}, {"name": "sftp", "emoji": "📁", "cat": "red", "simple": "Transferir archivos por SSH", "explain": "📂 Como FTP pero seguro. Navega y transfiere archivos usando la seguridad de SSH.", "example": "sftp usuario@servidor", "output": "sftp&gt; ls", "tipo": "instalar"}, {"name": "ip neigh", "emoji": "👥", "cat": "red", "simple": "Ver dispositivos en la red local", "explain": "🏘️ Como ver quién vive en tu barrio de internet. Lista los dispositivos en tu red local.", "example": "ip neigh", "output": "192.168.1.1  dev eth0  00:11:22:aa:bb:cc  REACHABLE", "tipo": "comando"}, {"name": "nmcli wifi", "emoji": "📶", "cat": "red", "simple": "Conectarse a WiFi desde terminal", "explain": "📡 Como seleccionar una red WiFi pero con texto. Conecta a redes inalámbricas sin usar el ratón.", "example": "nmcli wifi connect 'MiRed' password '12345'", "output": "(conectado a MiRed)", "tipo": "instalar"}, {"name": "brctl", "emoji": "🌉", "cat": "red", "simple": "Gestionar puentes de red", "explain": "🌉 Como crear un puente entre dos redes. Útil para virtualización y redes avanzadas.", "example": "sudo brctl show", "output": "bridge name  interfaces\nbr0          eth0", "tipo": "instalar"}, {"name": "ip tuntap", "emoji": "🔌", "cat": "red", "simple": "Crear interfaz de red virtual", "explain": "🕸️ Como crear un cable de red imaginario. Útil para VPNs y pruebas de red.", "example": "sudo ip tuntap add dev tun0 mode tun", "output": "(interfaz virtual tun0 creada)", "tipo": "instalar"}];